INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 1, 'Sin clasificar', 'Pregunta asociada a la imagen 1. Mujer de 42 años que acude a la consulta de genética por un diagnóstico reciente de cáncer de endometrio. En base a los antecedentes familiares que constan en la imagen, ¿cuál de los siguientes síndromes es más probable que presente?:', 'Poliposis adenomatosa familiar.', 'Síndrome de Lynch.', 'Síndrome de cáncer de mama y ovario hereditario.', 'Síndrome de Cowden.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 2, 'Sin clasificar', 'Pregunta asociada a la imagen 2. Paciente de 65 años que acude a urgencias por disminución brusca de agudeza visual en ojo derecho. La retinografía de dicho ojo se muestra en la imagen. Uno de los siguientes tratamientos está indicado para una enfermedad que es un factor de riesgo para esta situación. Indique cuál:', 'Latanoprost y timolol.', 'Flecainida.', 'Hidroxicloroquina.', 'Complejos vitamínicos y antioxidantes.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 3, 'Sin clasificar', 'Pregunta asociada a la imagen 3. Hombre de 70 años exfumador de un paquete al día y bebedor de 2 copas de vino al día consulta por una molestia faríngea de 1 mes de evolución. Se observa exudado amigdalar por lo que se inicia tratamiento antibiótico. El resultado del test de estreptococo es negativo. La clínica persiste y se añade odinofagia con otalgia refleja y leve cambio en el timbre de la voz. Nota un bulto duro de unos 2 cm a nivel II cervical ipsilateral no doloroso. La orofaringoscopia se refleja en la imagen asociada (imagen aumentada en el recuadro resaltado en rojo). ¿Cuál es la sospecha diagnóstica y su manejo?:', 'Resistencia bacteriana a antibioterapia recibida, precisa cultivo de exudado faríngeo con antibiograma para indicación adecuada.', 'Sospecha de absceso periamigdalino izquierdo, será remitido a urgencias de Otorrinolaringología para drenaje quirúrgico.', 'Sospecha de neoplasia maligna de amígdala palatina, será remitido preferente-urgente a Otorrinolaringología.', 'Sospecha de angina de Plaut-Vincent, remitido a Otorrinolaringología para realización de biopsia de ganglio para estudio de linfoma. Página:', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 4, 'Sin clasificar', 'Pregunta asociada a la imagen 4. Niña de 7 años que acude por otalgia y otorrea purulenta derecha desde hace 3 semanas, tratada con antibióticos y antinflamatorios. Tras la resolución de las manifestaciones clínicas, vuelve a aparecer la otorrea por lo que se pauta de nuevo tratamiento antibiótico. A los 5 días se objetiva una tumefacción retroauricular. En la otoscopia se pone de manifiesto una leve retracción de la membrana timpánica, escasa secreción blanquecina en el conducto auditivo externo y una tumefacción retroauricular blanda que ocasiona un mínimo desplazamiento anterior del pabellón auricular. Indique el diagnóstico que sugiere la imagen de resonancia magnética mostrada:', 'Absceso subperióstico extracraneal.', 'Trombosis venosa cerebral.', 'Absceso cerebral retromastoideo.', 'Área de cerebritis retromastoidea.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 5, 'Sin clasificar', 'Pregunta asociada a la imagen 5. Una mujer de 18 años acude a urgencias por dolor abdominal intenso, febrícula, test de embarazo positivo y manchado vaginal de 3 días de evolución junto con líquido libre intraabdominal en la ecografía. Se realiza una laparoscopia en la que se encuentra el siguiente hallazgo tras aspirar sangre de la cavidad abdominal. ¿Cuál es el diagnóstico más probable de los siguientes?:', 'Gestación ectópica.', 'Quiste de ovario complicado.', 'Apendicitis aguda.', 'Enfermedad inflamatoria pélvica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 6, 'Sin clasificar', 'Pregunta asociada a la imagen 6. Hombre de 40 años que presenta cefalea brusca con exploración neurológica normal. Se realiza TC craneal que se muestra en la imagen y una angiografía cerebral en la que no se encuentra patología subyacente. El cuadro clínico más probable es:', 'Hemorragia subaracnoidea traumática occipital.', 'Hemorragia causada por una malformación arteriovenosa angiográficamente oculta.', 'Hemorragia subraracnoidea perimesencefálica con un probable origen venoso o capilar.', 'Hemorragia causada por una discrasia sanguínea.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 7, 'Sin clasificar', 'Pregunta asociada a la imagen 7. Hombre de 75 años consulta por un cuadro de dificultad para la marcha de 2 años de evolución de forma progresiva. Presenta reflejos vivos en las cuatro extremidades. Se muestra la RM cervical realizada. Con respecto al cuadro clínico del paciente señale la respuesta INCORRECTA:', 'El cuadro de paraparesia puede ser asimétrico.', 'La progresión de la enfermedad es lenta pero puede acelerarse por movimientos de flexión o extensión cervical forzados.', 'Se trata de una enfermedad primaria de motoneurona.', 'La incontinencia urinaria aparece con la progresión de la enfermedad.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 8, 'Sin clasificar', 'Pregunta asociada a la imagen 8. Mujer de 14 años derivada a Rehabilitación para el manejo de una deformidad de la columna vertebral. Tuvo la menarquia a los 10 años. En la exploración física se aprecia mínima asimetría de escápulas, el eje occipito-sacro está centrado y en el test de Adams se observa una gibosidad torácica derecha de 10 mm. Se aporta telerradiografía de columna en proyección antero-posterior. ¿Cuál de los siguientes considera el manejo más adecuado a seguir?:', 'Observación, con recomendación específica de ejercicios y revisión posterior.', 'Corsé de Milwaukee a tiempo completo.', 'Corsé de Boston a tiempo parcial.', 'Derivación a cirugía para tratamiento quirúrgico.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 9, 'Sin clasificar', 'Pregunta asociada a la imagen 9. Hombre de 60 años de edad que tras dolor brusco y chasquido en hombro presenta la siguiente deformidad en el brazo. ¿Cuál es el diagnóstico más probable?:', 'Rotura de la porción larga del bíceps braquial.', 'Rotura de la porción corta del bíceps braquial.', 'Rotura del tendón distal del bíceps braquial.', 'Rotura del tendón del pectoral mayor. Página:', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 10, 'Sin clasificar', 'Pregunta asociada a la imagen 10. Paciente de 41 años, de talla baja, consulta por dolor en ambas caderas, más intenso en la izquierda. Refiere haber tenido dolor en caderas a edades tempranas aunque nunca consultaron por este motivo. Tras estudio radiográfico de caderas, se decide prótesis total de cadera izquierda, siguiendo buena evolución. Durante el postoperatorio el paciente refiere además dolor en hombros. Ante la sospecha diagnóstica se solicita una telerradiografía (ver imagen). Indique qué proceso es más probable que padezca el paciente desde su infancia:', 'Enfermedad de Perthes.', 'Osteonecrosis multifocal.', 'Epifisiolisis bilateral de cadera.', 'Displasia epifisaria múltiple.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 11, 'Sin clasificar', 'Pregunta asociada a la imagen 11. Hombre de 40 años que consulta por tumoración dolorosa en cara interna de rodilla. En el estudio radiográfico se obtiene esta imagen. ¿Cuál es el diagnóstico más probable?:', 'Osteomielitis.', 'Osificación heterotópica.', 'Encondroma.', 'Osteocondroma.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 12, 'Sin clasificar', 'Pregunta asociada a la imagen 12. Hombre de 80 años, fumador. Refiere en los últimos días episodios de mareos no relacionados con el ejercicio ni el estrés, de unos 3-4 minutos de duración. Solicita atención urgente en su domicilio tras presentar un síncope, con pérdida completa de conciencia, de unos 15-20 segundos de duración. La presión arterial es 110/40 mmHg. Se obtiene el ECG de la imagen. ¿Cuál es su diagnóstico?:', 'Infarto agudo de miocardio con elevación del segmento ST, anterior.', 'Bloqueo aurículo ventricular (AV) de primer grado.', 'Bloqueo AV de segundo grado, tipo II.', 'Bloqueo AV de tercer grado.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 13, 'Sin clasificar', 'Pregunta asociada a la imagen 13. Hombre de 75 años que consulta por palpitaciones de aparición súbita hace 1 hora, sin dolor torácico ni cortejo vegetativo asociado. Tiene antecedentes de hipertensión arterial, dislipemia, hipertrofia benigna prostática y accidente isquémico transitorio hace 12 años. PA 180/109 mmHg, FC 126 lpm, Sat O2 98%. Auscultación cardíaca tonos rítmicos, sin soplos audibles. Miembros inferiores sin edemas ni signos de trombosis venosa profunda. Se realiza ECG que se muestra en la imagen. Indique, de los siguientes, el diagnóstico más probable:', 'Fibrilación auricular.', 'Flutter auricular.', 'Infarto agudo de miocardio.', 'Taquicardia ventricular.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 14, 'Sin clasificar', 'Pregunta asociada a la imagen 14. Mujer de 69 años, obesa, con historia de apnea obstructiva del sueño, insuficiencia respiratoria hipercápnica, polimialgia reumática e hipotiroidismo de larga evolución. Acude a consulta en su centro de salud con los resultados de una tomografía computarizada (TC) solicitada por hallazgo de cardiomegalia en la Rx de tórax. Su frecuencia cardíaca es 68 lpm, y la presión arterial es 145/70 mmHg. Con inspiración profunda, sus cifras tensionales son 139/68 mmHg. Con estos datos clínicos y la imagen de la TC que se muestra, señale qué diagnóstico es más probable:', 'Neumotórax.', 'Taponamiento cardíaco con colapso de cavidades cardíacas.', 'Disección de aorta.', 'Derrame pericárdico crónico. Página:', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 15, 'Sin clasificar', 'Pregunta asociada a la imagen 15. Paciente de 72 años con antecedentes de cardiopatía isquémica que acude a Urgencias por astenia, disnea de esfuerzo y malestar general desde hace dos semanas. En analítica se objetiva hemoglobina 7,1 g/dL, leucocitos 9.330/µL (Neutrófilos 77%), plaquetas 15.6000/µL, creatinina sérica 7,6 mg/dL (previa 1,1 mg/dL), Na+ 139 mmol/L, K+ 5,2 mmol/L. Orina: Na+ 121 mmol/L, K+ 21,3 mmol/L, cociente proteína/creatinina 3,5 g/g, eritrocitos +3, leucocitos +3. Se realiza un TC de tórax que se muestra en la imagen. Indique la actitud más correcta en relación con su diagnóstico y tratamiento inicial:', 'Neumonía atípica con fracaso renal agudo secundario a necrosis tubular aguda y el tratamiento es la administración de antibióticos de amplio espectro y hemodiálisis.', 'Fracaso renal agudo parenquimatoso de probable origen glomerular con hemorragia alveolar asociada y el tratamiento es inmunosupresores y plasmaféresis.', 'Síndrome urémico hemolítico atípico y hay que plantear plasmaféresis y administración de eculizumab.', 'Fracaso renal agudo funcional secundario a insuficiencia cardíaca y hay que iniciar tratamiento con diuréticos a altas dosis y diálisis si no responde.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 16, 'Sin clasificar', 'Pregunta asociada a la imagen 16. Hombre de 68 años, exfumador desde hace 3 meses, con criterios clínicos de bronquitis crónica. Consulta por cuadro de pérdida de peso junto con astenia de un mes y medio de duración. Refiere tos seca ocasional y sensación distérmica sin fiebre termometrada. Tras realizarle la radiografía de tórax se solicita TC torácico que se muestra en la imagen. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Bronquiolitis respiratoria con enfermedad pulmonar intersticial.', 'Neumonía organizada criptogénica.', 'Atelectasia obstructiva de lóbulos inferiores por neoplasia central.', 'Neumonía intersticial inespecífica.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 17, 'Sin clasificar', 'Pregunta asociada a la imagen 17. Paciente de 63 años consulta por dolor en flanco derecho, ictericia y aumento del perímetro abdominal. Se realiza ecografía doppler y TC de hígado como se muestra en la imagen. ¿Cuál de las siguientes es la mejor opción terapéutica?:', 'Colocación de una derivación intrahepática percutánea (TIPS).', 'Anticoagulación oral.', 'Trasplante hepático.', 'Angioplastia percutánea.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 18, 'Sin clasificar', 'Pregunta asociada a la imagen 18. Mujer de 90 años que acude a urgencias por hipotensión, vómitos oscuros y dolor abdominal. Se realiza una TC abdominal que se muestra en la imagen. De las siguientes opciones, ¿cuál es la más probable?:', 'Se observa gas en el sistema portal siendo indicativo de mal pronóstico.', 'Se trata de una aerobilia y por tanto el diagnóstico más probable es el de colangitis.', 'Se observa aerobilia y pneumatosis gástrica.', 'Se trata de un hallazgo no relevante en relación con una CPRE o cirugía previa.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 19, 'Sin clasificar', 'Pregunta asociada a la imagen 19. Hombre de 60 años sin antecedentes de interés que acude a urgencias con un cuadro de 48 horas de fiebre de 38ºC y dolor abdominal en fosa iliaca izquierda. A la exploración abdominal destaca cierta defensa a la palpación sin peritonismo generalizado. La analítica sanguínea sólo destaca una discreta leucocitosis. La TC abdomino-pélvica se muestra en la imagen adjunta. ¿Cuál es el diagnóstico más probable?:', 'Cáncer de colon izquierdo oclusivo.', 'Síndrome de Ogilvie.', 'Diverticulitis aguda.', 'Megacolon tóxico o infeccioso. Página:', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 20, 'Sin clasificar', 'Pregunta asociada a la imagen 20. Hombre de 73 años con antecedentes de hipertensión arterial y diabetes mellitus tipo 2 que acude a urgencias por presentar desde hace una semana hiperglucemia mayor de 500 mg/dL. Refiere que comenzó con dolor en vacío derecho y vómitos autolimitados. Desde entonces, disminución de la ingesta, poliuria y sensación distérmica sin fiebre termometrada. Se realiza ecografía y TC abdominopélvica sin contraste intravenoso que se muestra en la imagen. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Pielonefritis enfisematosa obstructiva.', 'Necrosis papilar renal.', 'Pielonefritis xantogranulomatosa.', 'Absceso retroperitoneal perirrenal por apendicitis aguda evolucionada.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 21, 'Sin clasificar', 'Pregunta asociada a la imagen 21. Mujer de 57 años con enfermedad renal crónica que presenta astenia, hipotensión y cianosis en manos tras una sesión de diálisis. En la analítica se detecta anemia normocítica (Hb 7 g/dL, VCM 96 fL) con discreta reticulocitosis, leucocitos y plaquetas normales; aumento de LDH y hemoglobina libre en plasma elevada. El estudio inmunohematológico muestra un anticuerpo con especificidad anti-P. Se realiza frotis sanguíneo (ver imagen) mediante punción digital. El diagnóstico más probable es:', 'Síndrome hemofagocítico.', 'Hemoglobinuria paroxística a frigore.', 'Hemoglobinuria paroxística nocturna.', 'Crioglobulinemia.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 22, 'Sin clasificar', 'Pregunta asociada a la imagen 22. Mujer de 58 años acude a urgencias por dolor en la punta de los dedos de la mano. No tiene alergias conocidas, ni hábitos tóxicos. Entre los antecedentes explica tres abortos, una apendicetomía, sensación frecuente de reflujo retroesternal y, desde hace unos 5 años aproximadamente, presenta con la exposición al frío episodios de palidez en los dedos de ambas manos que cada vez se han hecho más intensos. A la vista de la imagen, ¿cuál de las siguientes actitudes se plantea realizar en primer lugar?:', 'Solicitar una TC torácica.', 'Valoración de tratamiento quirúrgico por cirugía vascular.', 'Determinación de ANA y anti-centrómero.', 'Tratamiento vasodilatador con prostaglandinas iv.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 23, 'Sin clasificar', 'Pregunta asociada a la imagen 23. En relación con un hombre de 74 años, que muestra alteraciones cognitivas y de la movilidad y en el cerebro neuronas con inclusiones citoplásmicas, como se observa en la imagen histológica, el diagnóstico más probable es:', 'Enfermedad de Alzheimer.', 'Demencia senil.', 'Enfermedad de Parkinson.', 'Encefalitis viral.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 24, 'Sin clasificar', 'Pregunta asociada a la imagen 24. Mujer de 35 años con historia de dolor abdominal recurrente que coincide con la menstruación. Los hallazgos de la intervención quirúrgica requieren una resección intestinal. El estudio anatomopatológico se muestra en la imagen. ¿Cuál es el diagnóstico más probable?:', 'Adenocarcimoma intestinal.', 'Metástasis de adenocarcinoma de endometrio.', 'Colitis ulcerosa.', 'Endometriosis.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 25, 'Sin clasificar', 'Pregunta asociada a la imagen 25. Hombre de 36 años con prácticas sexuales de riesgo. Presenta un cuadro de 4 días de evolución de lesiones cutáneas no pruriginosas (ver imagen). No ha tomado medicación previamente y no tiene antecedente de alergias farmacológicas. Se realiza serología para VIH que es negativa. La serología de sífilis antitreponema pallidum es positiva y RPR 1:32. Señale la respuesta correcta:', 'Se recomienda el análisis del líquido cefalorraquídeo.', 'La azitromicina oral es un tratamiento alternativo eficaz.', 'Se recomienda una valoración clínica y serológica (RPR) a los 6 y 12 meses después del tratamiento.', 'Si los títulos de RPR permanecen positivos después de 12 meses está indicado administrar el tratamiento de nuevo.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 26, 'Sin clasificar', 'Entre los cambios metabólicos que se observan en un paciente con resistencia a insulina existe:', 'Incremento de la expresión hepática de genes gluconeogénicos mediado por FOXO1 (forkhead box other) fosforilado.', 'Descenso en los niveles intracelulares de hexoquinasa 2 dependiente de insulina.', 'Aumento de la glucogenólisis muscular, contribuyendo al incremento de la glucemia.', 'Aumento en los niveles séricos de aminoácidos como leucina e isoleucina. Página:', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 27, 'Sin clasificar', 'La deficiencia de acil-CoA-deshidrogenasa provoca una de las siguientes alteraciones bioquímicas:', 'Disminución de ácidos dicarboxílicos.', 'Aumento de la gluconeogénesis.', 'Disminución de la ureagénesis.', 'Aumento de carnitina libre.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 28, 'Sin clasificar', 'Respecto a la técnica de exploración de la motilidad pupilar y sus reflejos indique la respuesta INCORRECTA:', 'El reflejo de la visión próxima se explora con una linterna que se enfoca sobre las pupilas de forma alternativa.', 'El signo pupilar de Marcus Gunn o defecto pupilar aferente relativo está presente en enfermedades del nervio óptico y enfermedades retinianas no extensas.', 'El reflejo fotomotor consensuado está afectado cuando el daño implica la vía eferente vehiculada por el nervio motor ocular común.', 'La anisocoria que aumenta en condiciones de oscuridad mostrando una pupila más miótica se debe a que hay un trastorno en el sistema simpático.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 29, 'Sin clasificar', 'En relación con el proceso de envejecimiento, respecto a los principales cambios morfológicos de los aparatos y sistemas, indique la respuesta INCORRECTA:', 'En el aparato respiratorio, calcificación de los cartílagos traqueales.', 'En el sistema nervioso, aumento del tamaño de los surcos interhemisféricos y de los ventrículos cerebrales.', 'En el aparato cardiovascular, reducción en el número de células marcapaso.', 'En el sistema nefrourológico, reducción del tejido mesangial.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 30, 'Sin clasificar', 'La utilización baja de energía por el músculo liso es fundamental para el gasto de energía corporal (órganos como los intestinos, la vejiga urinaria o la vesícula biliar mantienen una contracción muscular tónica casi indefinidamente). A este respecto, señale la afirmación correcta:', 'La disposición física de los filamentos de miosina y actina es similar a la del músculo esquelético.', 'En esa contracción, es fundamental la lentitud de la unión y separación de los puentes cruzados entre los filamentos de actina y miosina.', 'La fuerza máxima de contracción es con frecuencia menor que la que se produce en el músculo esquelético.', 'La contracción prolongada exige que la excitación de las fibras musculares se mantenga mientras lo haga esa contracción.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 31, 'Sin clasificar', 'En relación con el control químico de la respiración en condiciones fisiológicas señale la afirmación INCORRECTA:', 'Los quimiorreceptores carotídeos y aórticos detectan especialmente cambios en la presión parcial de O2 en la sangre.', 'Los quimiorreceptores carotídeos y aórticos reciben un flujo arterial muy elevado por lo que se consideran expuestos en todo momento a sangre arterial.', 'Los quimiorreceptores centrales detectan fundamentalmente cambios en la concentración de H+ (procedente sobre todo de la disociación de CO2 y H2O).', 'El efecto estimulador de la ventilación del CO2 se mantiene sin atenuación en los primeros días.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 32, 'Sin clasificar', 'En un paciente diagnosticado de una neoplasia maligna de nasofaringe que presenta dolor y edema orbitario, neuropatía de los pares craneales III, IV y VI, y neuropatía de la rama V1 del V par craneal, indique qué estructura es más probable que se encuentre infiltrada:', 'Seno cavernoso.', 'Hipófisis.', 'Agujero yugular.', 'Fosa pterigopalatina.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 33, 'Sin clasificar', 'Niña de 7 años con una sospecha de anemia de Fanconi. ¿Cuál de las siguientes manifestaciones clínicas NO se ajusta a los rasgos típicos de esta enfermedad?:', 'Anomalías pigmentarias.', 'Anomalías renales.', 'Anomalías esqueléticas.', 'Estatura alta.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 34, 'Sin clasificar', 'La exploración ecográfica de una mujer gestante de 26 semanas muestra hallazgos consistentes con osteogénesis imperfecta tipo II (gen COL1A1/COL1A2). La paciente tuvo un embarazo previo con la misma patología. Ni ella ni su pareja tienen manifestaciones clínicas de osteogénesis imperfecta. ¿Cuál de las siguientes es la explicación más probable para la recurrencia?:', 'Herencia autosómica recesiva.', 'Mutación de novo.', 'Penetrancia incompleta.', 'Mosaicismo germinal. Página:', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 35, 'Sin clasificar', 'Las vacunas contra el neumococo recomendadas para prevenir la enfermedad neumocócica en personas mayores de 65 años y en pacientes inmunocomprometidos pueden estar constituidas por polisacáridos del neumococo purificados (PPV23) o polisacáridos conjugados a proteínas (PCV15 o PCV20). Desde una perspectiva inmunológica las vacunas conjugadas:', 'No generan memoria inmunológica.', 'Activan una respuesta inmunitaria T-dependiente (o timo-dependiente).', 'No activan el proceso de hipermutación somática.', 'No inducen cambio de isotipo.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 36, 'Sin clasificar', 'El paso de autoanticuerpos de la madre al feto a través de la placenta puede asociarse a la aparición de enfermedades autoinmunes en el recién nacido. Señale cuál de las parejas Enfermedad – Autoanticuerpo es INCORRECTA:', 'Pénfigo vulgar – Anticuerpos antidesmogleina 3.', 'Bloqueo cardíaco congénito – Anticuerpos anti Ro y anti-La.', 'Miastenia gravis – Anticuerpos anti receptor de la acetilcolina.', 'Lupus eritematoso neonatal – Anticuerpos anti- Sm.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 37, 'Sin clasificar', 'Mutaciones en el gen Btk pueden causar una inmunodeficiencia primaria que cursa con la disminución drástica o ausencia de inmunoglobulinas en la sangre periférica (agammaglobulinemia). En relación al estudio de los pacientes con esta agammaglobulinemia, ¿cuál de las siguientes afirmaciones es cierta?', 'Es una enfermedad autosómica recesiva.', 'El porcentaje de linfocitos que expresan CD19 o CD20 (linfocitos B) en sangre periférica está dentro de los límites normales.', 'El nivel de IgG en suero disminuye paulatinamente desde el nacimiento hasta resultar indetectable.', 'La expresión de la proteína Btk en monocitos es normal.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 38, 'Sin clasificar', 'Hombre de 20 años que, tras ingesta de gambas, presenta de forma prácticamente inmediata prurito palmoplantar, sensación de nudo en la garganta y ronquera, mareo, sensación de inestabilidad y debilidad intensa. Entre sus antecedentes destaca cuadro de edema laríngeo por alergia a las lentejas al año de edad. No refiere alergia conocida a otros alimentos, tampoco reacciones adversas a fármacos ni picadura de insectos. Entre los antecedentes familiares tiene un hermano con rinitis alérgica leve intermitente por alergia a pólenes. ¿Cuál debe ser el tratamiento inicial de forma urgente?:', 'Hidrocortisona 500 mg IV y dexclorfeniramina 5 mg IV.', 'Adrenalina 0,3-0,5 mL IV.', 'Adrenalina 0,3-05 mL IM.', 'Metilprednisolona 40 mg IM y desclorfeniramina 5 mg IV.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 39, 'Sin clasificar', 'Hombre de 40 años sin antecedentes patológicos de interés, residente en una zona de interior de la península ibérica, que presentó cuadro de urticaria aguda por sensibilización a Anisakis simplex tras haber ingerido larvas vivas en unos boquerones en vinagre. El cuadro descrito le ocurrió hace más de 6 meses. Aporta prueba cutánea e IgE específica positiva frente a dicho parásito. En relación a la ingesta de pescados, ¿qué pauta de las que se indican a continuación debe seguir?:', 'Puede comer pescados y mariscos sin ningún tipo de precaución dado que han transcurrido más de 6 meses de la ingesta.', 'No puede ingerir ningún tipo de pescado.', 'Puede comer pescado cocinado a 45ºC.', 'Puede comer pescado previamente congelado a - 20ºC durante 72 horas en el domicilio o pescado congelado industrial.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 40, 'Sin clasificar', 'La medida adecuada para estimar el riesgo individual de enfermar es:', 'La incidencia acumulada.', 'La densidad de incidencia.', 'La prevalencia puntual.', 'El riesgo relativo. Página:', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 41, 'Sin clasificar', 'Al finalizar el periodo de seguimiento en el estudio PREDIMET (“Primary Prevention of Cardiovascular Disease with a Mediterranean Diet”), el 3,8% de los individuos asignados a dieta mediterránea presentaron algún tipo de evento cardiovascular (infartos de miocardio, ictus o muertes de origen cardiovascular), frente al 4,4% de eventos ocurridos en el grupo control. ¿Cuál es el número necesario de pacientes a tratar (NNT) con dieta mediterránea para evitar un evento cardiovascular?:', '26.', '60.', '80.', '167.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 42, 'Sin clasificar', 'En evaluación económica de intervenciones sanitarias, un estudio que compare los costes alternativos de dos intervenciones frente a sus resultados de salud expresados en años ajustados por calidad o años de vida ajustados por discapacidad se denomina:', 'Análisis coste-beneficio.', 'Análisis coste-efectividad.', 'Análisis coste-utilidad.', 'Análisis de minimización de costes.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 43, 'Sin clasificar', 'Señala la opción INCORRECTA respecto a la enfermedad meningocócica:', 'El mecanismo de transmisión es por gotas.', 'Se dispone de vacunas efectivas únicamente para la prevención de 4 subtipos de meningococo.', 'La vacuna frente a meningococo tipo B está incluida en el calendario sistemático de inmunizaciones del Sistema Nacional de Salud.', 'Ante un contacto de riesgo con un paciente con meningitis meningocócica, la vacunación del contacto no debe ser la primera estrategia de profilaxis postexposición.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 44, 'Sin clasificar', 'Se diagnostica de varicela a un niño de 8 años. Su madre está embarazada de 32 semanas y se le solicita una serología en la que se observan anticuerpos de tipo IgG frente a varicela por debajo de los niveles protectores y niega haber padecido la enfermedad en el pasado. ¿Cuál es la actitud recomendada con la gestante sabiendo que han pasado 3 días desde el inicio de la exposición?', 'Administrar una dosis de la vacuna frente a varicela.', 'Forzar la terminación del embarazo para poder vacunarla.', 'Es tarde para plantear una estrategia de profilaxis post-exposición.', 'Administrar gammaglobulinas polivalentes o hiperinmunes.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 45, 'Sin clasificar', 'En un metaanálisis, el riesgo relativo estimado para la asociación causal entre el uso de mascarilla y la incidencia de SARS-CoV-2 fue de 0,47. ¿Cuál es la interpretación correcta de este resultado?:', 'La incidencia de SARS-CoV-2 se reduce un 47% cuando la población usa mascarilla.', 'No usar mascarilla aumenta un 53% el riesgo de infección por SARS-CoV-2.', 'El uso de mascarilla podría evitar 47 de cada 100 casos de SARS-CoV-2 que se dan en personas que no la usan.', 'La incidencia de SARS-CoV-2 en la población que no usa mascarilla se reduciría un 53% si la utilizara.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 46, 'Sin clasificar', 'Hombre de 79 años de edad con antecedentes de hipertensión arterial, hiperuricemia y artrosis que acude a urgencias por presentar posible reacción adversa farmacológica. No refiere antecedentes alergológicos de interés. Después de una excursión en barco sin protección solar presenta un cuadro cutáneo agudo facial, principalmente en párpados superiores e inferiores, consistentes en eritema y edema intenso bilateral. El paciente estaba realizando tratamiento médico de forma habitual con hidroclorotiazida 25 mg, amlodipino 5 mg, atorvastatina 10 mg y apixaban 5 mg. ¿Cuál de los cuatro fármacos descritos es más probable que sea el responsable de una posible reacción de fotosensibilidad?', 'Hidroclorotiazida.', 'Amlodipino.', 'Atorvastatina.', 'Apixaban.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 47, 'Sin clasificar', '¿Con cuál de estos fármacos administrados en monoterapia es necesario realizar un ecocardiograma antes de su inicio?:', 'Trastuzumab.', 'Tamoxifeno.', 'Paclitaxel.', 'Docetaxel.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 48, 'Sin clasificar', 'La inducción de secuencia rápida en la anestesia general es:', 'Método de inducción anestésica utilizado cuando existe riesgo de regurgitación gástrica y aspiración pulmonar.', 'Método de inducción anestésica realizado exclusivamente con halogenados.', 'Procedimiento anestésico que requiere la ventilación del paciente con presión positiva.', 'Método de inducción anestésica utilizado habitualmente para la realización del procedimiento quirúrgico programado. Página:', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 49, 'Sin clasificar', 'Señale la actitud correcta ante un paciente en edad infantil que refiere antecedente de traumatismo facial no tratado hace 3 años y que presenta limitación progresiva de la apertura oral y desviación del mentón hacia un lado:', 'Debe descartarse la existencia de una fractura antigua tipo Lefort-1.', 'Debe realizarse un estudio mediante tomografía computarizada para descartar una displasia fibrosa.', 'Debe descartarse el diagnóstico de osteocondroma del cóndilo mandibular.', 'Debe descartarse el diagnóstico de anquilosis témporo-mandibular.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 50, 'Sin clasificar', 'Respecto al colgajo DIEP (Deep inferior epigastric perforator), señale la respuesta INCORRECTA:', 'Se trata de un colgajo basado en vasos perforantes que puede ser usado como colgajo libre o como colgajo pediculado.', 'Está irrigado por ramas de la arteria circunfleja femoral lateral.', 'Puede utilizarse para reconstrucción mamaria.', 'Los vasos perforantes musculocutáneos atraviesan el músculo recto del abdomen antes de irrigar la piel del colgajo.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 51, 'Sin clasificar', '¿Cuál de los siguientes escenarios podría suponer una contraindicación para el uso de un injerto de piel parcial como cobertura de un defecto cutáneo?:', 'Cuando el defecto cutáneo abarca una gran superficie corporal.', 'En un paciente con comorbilidades médicas significativas.', 'Cuando hay un tendón sin paratendón en la base de la herida.', 'Cuando hay una infección activa en el lecho de la herida.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 52, 'Sin clasificar', 'Un enfermo diabético de reciente diagnóstico acude a revisión oftalmológica. A las pocas horas vuelve con un cuadro bilateral de edema y eritema palpebral, quemosis, hiperemia conjuntival, lagrimeo y picor. Su actitud debe ser:', 'Solicitar una analítica con glucemia, hemoglobina glicosilada y velocidad de sedimentación globular.', 'Prescribir un colirio antihistamínico o corticoide de baja potencia.', 'Realizar una OCT (tomografía de coherencia óptica) para descartar la existencia de un edema macular diabético.', 'Realizar una gonioscopia para descartar la presencia de neovasos en el ángulo camerular.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 53, 'Sin clasificar', 'En relación al tratamiento quirúrgico de las cataratas, señale cuál de los siguientes enunciados es correcto:', 'El empeoramiento de la visión cercana está inducido por la catarata y se denomina miopía de índice.', 'La cirugía de cristalino disminuye el riesgo de desprendimiento de retina en los pacientes miopes jóvenes.', 'Las cataratas se operan cuando la agudeza visual está muy disminuida sin tener en cuenta otros síntomas o signos.', 'Los fármacos alfa bloqueantes como la tamsulosina asocian complicaciones intraoperatorias.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 54, 'Sin clasificar', 'Hombre de 72 años exfumador, acude a consulta por visión borrosa y dificultad para leer, especialmente en el ojo derecho, situación que ha progresado lentamente en los últimos seis meses. En la exploración del segmento anterior no se encuentran alteraciones clínicamente relevantes. En el ojo derecho se observan múltiples drusas en la región macular (una de tamaño grande) y alteraciones pigmentarias. En la tomografía de coherencia óptica se muestra un adelgazamiento del epitelio pigmentario de la retina y áreas de acumulación de material subretiniano en la mácula del ojo derecho. ¿Cuál es el manejo inicial indicado para este paciente?:', 'Iniciar tratamiento con implante intravítreo de dexametasona.', 'Recomendar el uso de suplementos vitamínicos específicos.', 'Indicar de forma preferente cirugía de catarata con implante de lente intraocular.', 'Iniciar tratamiento con inyecciones intravítreas de anti-VEGF (factor de crecimiento endotelial vascular). Página:', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 55, 'Sin clasificar', 'Hombre de 26 años que presenta otorrea unilateral derecha de una semana de evolución desde su regreso de vacaciones en la playa donde una ola le arrolló provocando inmersión. Refiere haber sido tratado en la infancia con colocación de drenajes transtimpánicos bilaterales y ha evitado la entrada de agua en los oídos desde entonces. No presenta dolor, pero sí molestias y leve hipoacusia. Tampoco tiene vértigo, pero sí sensación de taponamiento ótico. En la otoscopia se evidencia una perforación timpánica central de bordes lisos y otorrea que proviene de oído medio. ¿Cuáles son el diagnóstico y tratamiento del paciente?:', 'Reactivación de una otitis media crónica simple que será tratada con ciprofloxacino en gotas óticas y remitir a Otorrinolaringología.', 'Otitis media aguda que precisa tratamiento con gentamicina en gotas óticas y revisión otoscópica pasada una semana.', 'Otitis media crónica colesteatomatosa que será tratada con gentamicina en gotas óticas y remitir a Otorrinolaringología.', 'Otitis externa aguda complicada que precisa tratamiento con ciprofloxacino en gotas óticas y revisión otoscópica pasada una semana.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 56, 'Sin clasificar', 'Hombre de 40 años que acude a urgencias por presentar un cuadro de mareo con giro de objetos acompañado de náuseas, vómitos, palidez y sudoración de varias horas de evolución. Nunca había presentado un cuadro similar. No refiere hipoacusia ni acúfeno ni sensación de taponamiento. La otoscopia es normal. Se observa un nistagmo horizonto-rotatorio hacia el lado derecho grado III que aumenta la velocidad cuando dirige la mirada a la derecha, maniobra oculocefálica positiva izquierda, test de Skew y el test de Romberg positivo a la izquierda. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Infarto cerebral.', 'Neuritis vestibular.', 'Enfermedad de Meniére.', 'Vértigo posicional paroxístico benigno.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 57, 'Sin clasificar', 'Mujer de 54 años consulta por hipoacusia unilateral derecha de horas de evolución que se ha presentado de manera brusca. Presentó un cuadro viral de vía aerodigestiva superior hace unos días. Sin antecedentes de interés, no presenta vértigo ni sensación de taponamiento ótico ni acúfeno. No refiere dolor ni presenta parálisis facial. La otoscopia es normal. En la acumetría la prueba Rinne es positiva bilateral y la pruebas Weber lateraliza al lado izquierdo. ¿Cuál es la sospecha diagnóstica y el manejo?:', 'Hipoacusia súbita, se solicitará una tomografía computerizada craneal urgente.', 'Hipoacusia de conducción por otitis media serosa, se tratará con lavados nasales y esteroides tópicos nasales.', 'Hipoacusia súbita, precisa audiometría tonal urgente y se tratará con corticoterapia sistémica y/o intratimpánica.', 'Síndrome de Ramsay-Hunt se tratará con corticoterapia más valaciclovir.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 58, 'Sin clasificar', 'Mujer que acude a ecografía de rutina de segundo trimestre a las 22 semanas de gestación. Las biometrías corresponden a un feto de 19 semanas. ¿Cuál es el siguiente paso para orientar el caso?:', 'Valorar estudio genético teniendo en cuenta el riesgo de anomalía cromosómica en primer trimestre.', 'Valorar si la gestación está correctamente datada según la longitud craneocaudal fetal de la ecografía del primer trimestre.', 'Repetir ecografía para nuevas biometrías en 2 semanas.', 'Estudio para descartar preeclampsia.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 59, 'Sin clasificar', '¿Cuál de los siguientes métodos anticonceptivos es el más adecuado para una mujer de 35 años con migraña con aura?:', 'Anticonceptivos orales combinados.', 'Parche anticonceptivo.', 'Anticonceptivo inyectable con estrógeno y progestágeno.', 'Dispositivo intrauterino (DIU) con levonorgestrel. Página: 1', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 60, 'Sin clasificar', 'Mujer con gestación monocorial biamniótica de 22 semanas que acude a urgencias por dinámica uterina ocasional. En la ecografía se observa feto 1 con peso estimado en el percentil 80 y columna máxima vertical de líquido amniótico de 11 cm, vejiga urinaria distendida y aumentada de tamaño y feto 2 con un peso en el percentil 25 con una columna máxima de líquido amniótico de 0,5 cm y vejiga urinaria no visible. Exploración vaginal anodina. La longitud cervical es de 36 mm. ¿Cuál es el diagnóstico más probable?:', 'Trasfusión feto-fetal.', 'Discordancia de crecimiento fetal con crecimiento fetal restringido selectivo del feto 2.', 'Rotura prematura de membranas de feto 2.', 'Malformación renal feto 2.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 61, 'Sin clasificar', 'Puérpera de parto eutócico sin complicaciones hace 4 días que acude a urgencias por cefalea de 12 horas de evolución y edemas maleolares. A la exploración presenta cifras tensionales de 165/100 mmHg en dos ocasiones y en la analítica se observa una cifra de plaquetas de 254.000/µL, AST 172 UI/L, ALT 154 UI/L y LDH 345 UI/L, creatinina 0,9 mg/dL y cociente prot/creat 235 mg/g. ¿Cuál de las siguientes opciones terapéuticas forma parte de la primera línea de tratamiento inmediato?', 'Sulfato de magnesio vía endovenosa.', 'Labetalol vía oral.', 'Corticoides a dosis altas.', 'Diuréticos vía endovenosa.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 62, 'Sin clasificar', '¿Cuál es la vía de diseminación más frecuente y característica del cáncer de ovario en el momento del diagnóstico?:', 'Vía linfática.', 'Vía hematógena.', 'Infiltración por contigüidad.', 'Diseminación peritoneal.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 63, 'Sin clasificar', '¿Cuál de las siguientes es una de las características que condiciona de modo crucial e independiente la elección del tratamiento adyuvante del cáncer de endometrio?:', 'Tamaño tumoral.', 'Perfil molecular del tumor.', 'Presencia de células tumorales aisladas en los ganglios linfáticos.', 'Presencia de metrorragia.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 65, 'Sin clasificar', 'Niña de 10 meses, correctamente vacunada para su edad, tiene fiebre alta, fotofobia y tos. Tras 4 días de fiebre se aprecian unas manchas blancas, como un espolvoreado de harina en mucosa malar a nivel del 2º molar. Al día siguiente de detectarse estas manchas, todavía con fiebre y tos, se detecta un exantema eritematoso, maculo-papuloso morbiliforme, con tendencia a la confluencia en algunas zonas, de aparición craneocaudal. La fiebre persiste hasta 3 días más. Al 5º día de iniciar el exantema el niño se encuentra afebril pero inicia en la piel una fase de descamación fina, furfurácea. El diagnóstico clínico más probable es:', 'Sarampión.', 'Rubeola.', 'Varicela.', 'Escarlatina.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 66, 'Sin clasificar', 'El síndrome de Guillain-Barré es considerado una polineuropatía postinfecciosa que presenta todas las características siguientes, EXCEPTO una:', 'Existe hiperreflexia tendinosa en las extremidades que manifiestan debilidad.', 'Es predominantemente un trastorno motor, aunque puede haber síntomas sensitivos.', 'En el líquido cefalorraquídeo las proteínas están elevadas, sin pleocitosis y con glucorraquia normal.', 'El tratamiento con inmunoglobulina intravenosa acelera la recuperación, pero no modifica la evolución a largo plazo. Página: 1', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 67, 'Sin clasificar', 'Un lactante de 6 meses acude a urgencias por presentar vómitos y diarrea en las últimas 12 horas. Su peso es de 6 kg. Hace 24 horas su peso era de 6,5 kg. Presenta frecuencia cardíaca 140 lpm, frecuencia respiratoria 30 rpm, presión arterial 90/40 mmHg. En la gasometría venosa se observa pH 7,25, pCO2 33 mmHg, pO2 45 mmHg, bicarbonato 17 mmol/L, exceso de bases -7, lactato 2,5 mmol/L. El sodio es 143 mmol/L. ¿Cuál es su situación en el equilibrio ácido base?:', 'Acidosis metabólica sin compensar respiratoriamente.', 'Acidosis metabólica parcialmente compensada respiratoriamente.', 'Acidosis respiratoria parcialmente compensada metabólicamente.', 'Alcalosis respiratoria compensada metabólicamente.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 69, 'Sin clasificar', 'Respecto a las medidas a tomar ante un niño diagnosticado de tos ferina, en relación a sus contactos, indique la respuesta INCORRECTA:', 'Tratar con antibióticos a toda la familia, independientemente de la edad, estado de inmunización y sintomatología.', 'Tratar con antibióticos a todo el personal sanitario que ha atendido al niño independientemente de la edad, estado de inmunización y sintomatología.', 'Vacunar a los adultos convivientes, aunque hayan padecido la enfermedad ya que la inmunidad no dura toda la vida.', 'Aislar al paciente al menos 5 días después de iniciar el tratamiento.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 70, 'Sin clasificar', 'Indique la respuesta FALSA respecto a la invaginación intestinal en pediatría:', 'La mayoría de los casos de invaginación en niños se deben a adherencias congénitas.', 'La incidencia estacional alcanza picos en otoño e invierno.', 'Se ha apreciado una correlación con infección respiratoria previa o concurrente por adenovirus (tipo C).', 'Se ha observado un aumento ligero de la invaginación en las tres semanas posteriores a la vacuna de rotavirus (sobre todo tras la primera dosis).', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 71, 'Sin clasificar', 'Todas las siguientes pueden ser manifestaciones tardías de sífilis congénita, habitualmente no evidentes clínicamente en los 2 primeros años de vida. Indique la manifestación que NO es habitual en esta patología:', 'Dientes de Hutchinson.', 'Nariz en silla de montar.', 'Queratitis intersticial.', 'Cardiopatía congénita.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 72, 'Sin clasificar', 'Mujer de 35 años que hace dos días sufrió un accidente de coche sin apenas consecuencias físicas acude a su médica de atención primaria, por insomnio con pesadillas, expresa también recuerdos vívidos de detalles del accidente y síntomas de hiperactivación. El diagnóstico más probable es:', 'Reacción aguda de estrés.', 'Reacción adaptativa depresiva.', 'Trastorno de estrés postraumático.', 'Trastorno de ansiedad generalizada.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 73, 'Sin clasificar', 'Los mecanismos de defensa que con mayor frecuencia se presentan en el trastorno delirante son los siguientes, EXCEPTO:', 'Proyección.', 'Negación.', 'Formación reactiva.', 'Regresión. Página: 1', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 74, 'Sin clasificar', 'Sobre los factores de mal pronóstico en la esquizofrenia, señale la respuesta INCORRECTA:', 'Inicio en edad temprana.', 'Presencia de síntomas negativos.', 'Presentación clínica aguda.', 'Antecedentes de agresividad.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 75, 'Sin clasificar', 'Adolescente de 16 años que es traída a la consulta por sus padres debido a cambios drásticos en su comportamiento en los últimos seis meses. Ha mostrado síntomas de depresión, irritabilidad y recientemente ha comenzado a autolesionarse realizándose cortes en los brazos. También se ha aislado socialmente y ha tenido dificultades para mantener su rendimiento académico. ¿Cuál de los siguientes factores es el más significativo para indicar desregulación emocional y riesgo de conducta suicida en esta paciente?:', 'Presencia de autolesiones.', 'Aislamiento social.', 'Irritabilidad.', 'Dificultades académicas.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 76, 'Sin clasificar', 'Mujer de 28 años con diagnóstico de trastorno bipolar tipo I embarazada de 12 semanas. Ha tenido episodios maníacos y depresivos en el pasado. Actualmente, está preocupada por el impacto de su tratamiento en el feto. ¿Cuál de los siguientes tratamientos es más seguro y recomendado durante el embarazo, y qué tipo de psicoterapia es apropiada como complemento?:', 'Ácido valproico y terapia interpersonal.', 'Lamotrigina y terapia cognitivo-conductual.', 'Litio y terapia cognitivo-conductual.', 'Carbamazepina y terapia interpersonal.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 77, 'Sin clasificar', 'Respecto a la enfermedad de Alzheimer, señale la respuesta INCORRECTA:', 'El gen de la ApoE (apolipoproteína epsilon ) alelo E4 es factor de riesgo.', 'Hay un descenso de la proteína tau en el LCR.', 'El PET tau y el PET amiloide son útiles en el diagnóstico precoz de la enfermedad.', 'En la RM de estos pacientes esperamos encontrar atrofia en el lóbulo temporal medial.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 78, 'Sin clasificar', 'Un paciente acude a la consulta porque tiene un trastorno de la marcha, tropieza y tiene caídas frecuentes. En la exploración presenta temblor de reposo en el miembro superior derecho, rigidez en rueda dentada al movilizarle las extremidades superiores y marcha alterada desplazando el tronco hacia delante con pasos cortos. ¿Cuál de las siguientes afirmaciones apoyaría el diagnóstico de enfermedad de Parkinson?:', 'Falta de respuesta inicial al tratamiento con Levodopa.', 'SPECT con transportador de dopamina que muestre una hipocaptación en la vía nigroestriada.', 'Gammagrafía miocárdica con MIBG (metayodobencilguanidina) normal.', 'Presencia precoz de síntomas de disautonomía.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 79, 'Sin clasificar', 'Mujer de 35 años consulta por cuadro de diplopia y debilidad proximal progresivas que empeora a lo largo de día. En la exploración neurológica se aprecia voz nasal, ptosis bilateral sin afectación pupilar, limitación para la abducción de ojo derecho y debilidad proximal con reflejos miotáticos conservados. Respecto a esta paciente señale la opción INCORRECTA:', 'El nivel de anticuerpos es independiente de la gravedad de la enfermedad.', 'En ocasiones se asocia a otra enfermedad autoinmune.', 'Es frecuente la agregación familiar.', 'La respuesta a inmunosupresores es mayor en pacientes con anticuerpos antirreceptor de acetilcolina y anticuerpos antiMusk positivos.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 80, 'Sin clasificar', 'Con respecto a la parálisis facial, ¿cuál de los siguientes signos y síntomas nos haría pensar en un origen central?', 'La presencia de ageusia asociada a la parálisis facial.', 'La presencia de hipoestesia o dolor en la región del pabellón auricular del mismo lado que la parálisis.', 'Si la debilidad de los músculos faciales sólo afecta a la mitad inferior de la hemicara afectada sin afectación de los músculos palpebrales ni de la frente.', 'Si hay disminución de la secreción lacrimal en el ojo correspondiente al lado de la parálisis facial. Página: 1', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 81, 'Sin clasificar', 'Hombre de 75 años con antecedentes de fibrilación auricular e hipertensión arterial es traído a urgencias por hemiparesia derecha, dificultad para hablar y fiebre de 38,5°C. La tomografía computarizada (TC) de cráneo revela un infarto cerebral en la región parietal izquierda e ingresa en la unidad de ictus. A las 48 h del ingreso se informa de presencia de Streptococcus viridans en hemocultivo. ¿Cuál es el diagnóstico más probable y el enfoque diagnóstico-terapéutico adecuado en este caso?', 'Accidente cerebrovascular isquémico secundario a fibrilación auricular; iniciar anticoagulación y antipiréticos.', 'Meningitis bacteriana con complicación isquémica; realizar punción lumbar e iniciar antibiótico dirigido según antibiograma.', 'Endocarditis infecciosa con embolia séptica; confirmar con ecocardiograma y tratar con antibiótico dirigido según el antibiograma.', 'Neoplasia cerebral con fiebre paraneoplásica; realizar resonancia magnética cerebral y evaluación oncológica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 82, 'Sin clasificar', 'Mujer de 55 años que consulta por una cefalea con sensación de presión bilateral, que no asocia fotofobia, náuseas ni vómitos. La paciente puede realizar sus actividades habituales porque el dolor es de intensidad moderada. El dolor es prácticamente diario en los últimos 6 meses. Desde el punto de vista terapéutico, ¿cuál es la opción más adecuada?', 'Tratamiento analgésico simple con paracetamol diario, los días que tenga dolor.', 'Tratamiento con triptanes en el momento agudo de la cefalea los días que sea más intensa.', 'Tratamiento preventivo de entrada con betabloqueantes tipo propranolol a dosis entre 40- 160 mg/d entre 3-6 meses.', 'Tratamiento preventivo de entrada con amitriptilina a dosis bajas entre 25-50 mg/d y mantenerlo entre 3 y 6 meses.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 83, 'Sin clasificar', 'Mujer de 18 años sin antecedentes de interés ni consumo de tóxicos que ingresa en planta por un cuadro de alteración conductual con ansiedad, agresividad e ilusiones visuales. Durante su ingreso presenta una crisis convulsiva junto con discinesias orolinguales y distonía del pie izquierdo. Dos semanas previas había presentado un cuadro de diarrea, náuseas y vómitos autolimitados. Respecto a este síndrome señale la respuesta INCORRECTA:', 'La encefalitis anti NMDAR es la encefalitis autoinmune más frecuente.', 'La RM con hiperseñal hipocampal es patognomónica de la enfermedad.', 'Existe una fuerte asociación con patología tumoral.', 'El pronóstico habitualmente es favorable.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 84, 'Sin clasificar', 'Hombre de 81 años con antecedentes de HTA, dislipemia y enfermedad de Alzheimer leve. Avisa su familia porque lo han encontrado en su casa caído en el suelo y no es capaz de movilizar extremidades derechas. Llega al hospital trasladado por emergencias como código ictus. A la exploración física destaca paresia facial derecha supranuclear, afasia global, hemianopsia derecha y hemiplejia de miembros derechos. La TC craneal se informa como ASPECTS 8 sin datos de sangrado. En angioTC oclusión de segmento M2 de división anterior de ACM izquierda. ¿Cuál de los siguientes es el mejor tratamiento inicial para este paciente?', 'Fibrinolisis con alteplasa.', 'Doble antiagregación y estatinas.', 'Manejo conservador por los antecedentes del paciente.', 'Trombectomía mecánica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 85, 'Sin clasificar', 'Sobre el tratamiento quirúrgico de la enfermedad de Parkinson señale la opción correcta:', 'Los núcleos diana principales son el núcleo pálido y el núcleo ventral inferomedial del tálamo.', 'La cirugía lesional es la opción utilizada más frecuentemente hoy en día.', 'La presencia de síntomas o signos que no responden a la levodopa desaconsejan el tratamiento.', 'La estimulación eléctrica de los núcleos genera una activación de los mismos, principio fundamental del tratamiento.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 86, 'Sin clasificar', 'El APACHE-II (Acute Physiologic Assessment and Chronic Health Evaluation II) es un índice cuantitativo de gravedad que se calcula en el paciente crítico utilizando las siguientes variables, EXCEPTO:', 'Recuento de leucocitos en sangre.', 'Escala de coma de Glasgow.', 'Lactato en sangre.', 'pH en sangre.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 87, 'Sin clasificar', 'Mujer de 57 años ingresada en la Unidad de Cuidados Intensivos por hipotensión persistente y fracaso multiorgánico. Tras monitorización hemodinámica avanzada, la paciente presenta frecuencia cardíaca de 105 lpm, resistencias vasculares sistémicas de 400 din-seg-m2/cm5, gasto cardíaco de 8 L/min, presión venosa central de 5 mmHg, variación del volumen sistólico del 9% e índice de agua pulmonar extravascular indexado de 5 mL/kg. ¿A qué tipo de shock orienta dicha monitorización hemodinámica avanzada?:', 'Shock distributivo.', 'Shock cardiogénico.', 'Shock hipovolémico.', 'Shock obstructivo. Página: 1', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 88, 'Sin clasificar', 'Mujer de 63 años, diabética en tratamiento con antidiabéticos orales que consulta por dolor en hombro derecho de 3 meses de evolución sin antecedente traumático. El dolor le limita el movimiento completo del hombro y desde hace una semana le impide el descanso nocturno. En la exploración el médico constata limitación para el movimiento activo de la abducción a más de 100º, de la flexión a 110º, rotación externa a 45º e interna lleva la mano al glúteo con dificultad. No presenta limitación en la movilidad pasiva de la extremidad. La orientación diagnóstica más probable y la actuación inicial es:', 'Tendinosis del manguito rotador. Crioterapia, AINEs tópicos y cabestrillo una semana.', 'Tendinosis cálcica del supraespinoso derecho. Crioterapia 3 veces al día e indicar fisioterapia.', 'Tendinosis del supraespinoso derecho. Infiltración, paracetamol cada 8 horas y solicitar resonancia magnética.', 'Tendinosis del supraespinoso derecho. Crioterapia, AINEs orales y ejercicios en su domicilio. Visita de control y si no mejora solicitar prueba de imagen.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 89, 'Sin clasificar', 'Jugador de baloncesto de 42 años que acude a urgencias por dolor de tres días de evolución en cara anterior de muslo derecho de tipo lancinante. Inicia el dolor tras mal gesto en flexión de la columna lumbar, presentando primero lumbalgia y después este dolor irradiado. En la exploración presenta un Lasegue invertido positivo, con un reflejo osteotendinoso rotuliano derecho 2/4. No hay déficit motor. La orientación diagnóstica más probable es:', 'Hernia discal L4-L5 migrada posterior que ocasiona una clínica de silla de montar.', 'Hernia discal foraminal L4-L5 derecha que comprime la raíz de L4.', 'Hernia discal foraminal L4-L5 derecha que comprime la raíz de L5.', 'Meralgia parestésica derecha.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 90, 'Sin clasificar', 'Paciente de 75 años con estancia prolongada en UCI. En una exploración rutinaria se observa dificultad para la flexión dorsal del pie izquierdo con un tibial anterior a 1/5, una dificultad para la extensión de los dedos 1/5 y dificultad para la eversión con peroneos 3/5. No presenta otro foco neurológico, ni dolor en la región lumbar ni en la extremidad. ¿Cuál de las siguientes es la actitud más correcta?:', 'Indicar férula antiequino y fisioterapia por sospecha de compresión del nervio ciático poplíteo externo.', 'Solicitar electromiograma urgente y dejarlo en reposo.', 'Realizar punción lumbar por sospecha de complicación por Guillain-Barre.', 'Solicitar resonancia magnética y pautar, si no está recibiendo, corticoides.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 91, 'Sin clasificar', 'Mujer de 19 años que, practicando patinaje sobre ruedas, sufre un traumatismo indirecto de la rodilla derecha, con luxación de rótula tratada en urgencias. Acude a revisión 2 meses más tarde y refiere que nota dolor y sensación de inestabilidad y subluxación frecuente con la actividad física. De los siguientes elementos, señale el que NO favorece la inestabilidad fémoro-patelar:', 'Anteversión femoral.', 'Torsión tibial interna.', 'Genu valgo.', 'Patela alta.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 92, 'Sin clasificar', 'Desde el punto de vista fisiopatológico la osteonecrosis de la cabeza femoral se puede desencadenar por todos los mecanismos aquí descritos EXCEPTO:', 'Anomalías en el flujo vascular por factores genéticos.', 'Oclusión intravascular por émbolos (lípidos, nitrógeno, hematíes anómalos).', 'Dehiscencia de la íntima arterial de los vasos.', 'Compresión extravascular a consecuencia de un acúmulo graso.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 93, 'Sin clasificar', 'Mujer de 68 años con IMC 28 kg/m2 que consulta por dolor crónico en rodilla derecha. Refiere que el dolor empeora con la actividad física, especialmente al subir y bajar escaleras, y mejora con el reposo. En la exploración física se observa crepitación en la rodilla derecha y leve deformidad en ambas. Una radiografía de rodilla derecha muestra estrechamiento del espacio articular y formación de osteofitos. ¿Cuál es la opción de tratamiento más adecuada en este caso?:', 'Inmovilización de la rodilla con rodillera de descarga rotuliana.', 'Pérdida de peso y ejercicio físico supervisado para fortalecer el cuádriceps.', 'Infiltración intraarticular de corticoides.', 'Tratamiento farmacológico con tramadol.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 94, 'Sin clasificar', 'Hombre de 30 años que acude a consulta por dolor lumbar crónico que empeora en la noche y mejora con el ejercicio. Refiere rigidez matutina de más de una hora. La exploración física revela una disminución de la movilidad en la columna lumbar y dolor a la palpación y exploración de las articulaciones sacroilíacas. La resonancia magnética muestra edema en las articulaciones sacroilíacas compatible con sacroileitis. ¿Cuál es el tratamiento inicial más indicado para este paciente?:', 'Metotrexate subcutáneo semanal.', 'Corticoides orales.', 'Fisioterapia y antiinflamatorios no esteroides (AINEs).', 'Terapia biológica con anti-TNF. Página: 1', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 95, 'Sin clasificar', 'Mujer de 83 años hospitalizada por neumonía adquirida en la comunidad por neumococo. Presenta una artritis aguda de carpo derecho. Sospechamos enfermedad por depósito de pirofosfato pero no se observa condrocalcinosis en la radiografía de carpos ni se ha conseguido obtener líquido sinovial durante la artrocentesis. ¿Qué radiografías añadiremos al cribado con el objetivo de identificar condrocalcinosis?:', 'Radiografía anteroposterior de rodillas y de sínfisis de pubis.', 'Radiografía anteroposterior de rodillas y de hombros.', 'Radiografía anteroposterior de sínfisis de pubis y de hombros.', 'Radiografía anteroposterior de rodillas y de codos.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 96, 'Sin clasificar', 'Uno de estos hallazgos anatomopatológicos sugiere el diagnóstico de enfermedad por IgG4:', 'Trombosis arterial.', 'Proliferación de la íntima arterial sin datos de vasculitis.', 'Fibrosis estoriforme.', 'Infiltrado perivascular de polimorfonucleares.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 97, 'Sin clasificar', '¿Cuál de los siguientes hallazgos NO esperaría encontrar en una mujer de 28 años con una comunicación interauricular evolucionada?:', 'Soplo mesosistólico.', 'Aumento de la silueta cardíaca en la radiografía de tórax.', 'Bloqueo de rama derecha en el electrocardiograma.', 'Hipertrofia del ventrículo izquierdo.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 98, 'Sin clasificar', 'Joven de 16 años con astenia desde hace 1 mes, que durante un partido de fútbol sufre un síncope. A su llegada al hospital inconsciente y hemodinámicamente inestable presenta síntomas y signos de accidente cerebrovascular, de isquemia mesentérica y de isquemia arterial periférica, en miembro superior izquierdo y de ambos miembros inferiores. ¿Cuál cree que es el diagnóstico de sospecha?:', 'Bloqueo aurículo-ventricular de 3º grado.', 'Insuficiencia mitral aguda.', 'Mixoma de aurícula izquierda.', 'Rotura de aneurisma de arteria cerebral media.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 99, 'Sin clasificar', 'Hombre de 65 años, hipertenso desde hace 12 años, que acude por primera vez a la consulta de su médico de familia para una revisión rutinaria. La exploración física es normal y el electrocardiograma muestra ritmo sinusal a 68 lpm, con bloqueo de la rama izquierda del haz de His y duración del QRS de 150 ms. ¿Cuál de las siguientes situaciones implica este hallazgo?:', 'Asincronía ventricular.', 'Miocardiopatía dilatada.', 'Disociación aurículo-ventricular.', 'Isquemia miocárdica aguda.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 100, 'Sin clasificar', 'Un entrenamiento aeróbico intenso y prolongado produce una serie de adaptaciones cardiovasculares que suelen denominarse "corazón de deportista". Entre las siguientes adaptaciones fisiológicas, señale la respuesta INCORRECTA:', 'Bradicadia sinusal por aumento del tono vagal.', 'Bloqueo aurículo-ventricular de primer grado, de segundo grado Mobitz I e incluso de tercer grado durante el sueño.', 'Bloqueo completo de rama izquierda del haz de His por hipertrofia ventricular izquierda.', 'Bloqueo de rama derecha del haz de His por dilatación fisiológica ventricular derecha en deportes de resistencia.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 101, 'Sin clasificar', '¿Cuál de las siguientes complicaciones es más frecuente en el reemplazo valvular aórtico transcatéter (TAVI) respecto del reemplazo valvular quirúrgico?:', 'Atelectasia pulmonar.', 'Bloqueo aurículo-ventricular completo.', 'Derrame pericárdico.', 'Hemorragia grave.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 102, 'Sin clasificar', 'Señale cuál de las siguientes situaciones se considera indicación de cirugía para el tratamiento de endocarditis infecciosa (EI):', 'Aparición de insuficiencia renal aguda.', 'Hallazgo por imagen de émbolos esplénicos o renales en el momento del diagnóstico.', 'Presencia de vegetaciones mayores de 8 mm en válvula tricúspide en la EI derecha.', 'Hemocultivos positivos persistentes durante 7-10 días tras pauta antibiótica adecuada. Página: 1', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 103, 'Sin clasificar', 'Hombre de 68 años, hipertenso y fumador que acude a urgencias por dolor torácico y disnea desde hace 3 horas. Presenta mal estado general, presión arterial 118/45 mmHg, FC 105 lpm, saturación O2 96%. En la auscultación crepitantes basales finos, tonos cardíacos atenuados, que no permiten identificar soplos. Dímero D 16.000 ng/mL. El ECG muestra taquicardia sinusal y signos de hipertrofia ventricular izquierda. Un ecocardiograma urgente revela un ventrículo izquierdo hipertrófico, no dilatado, con disfunción sistólica global ligera, insuficiencia aórtica moderada, no conocida previamente y derrame pericárdico moderado-grave. Con estos datos, ¿qué patología debe descartar?:', 'Disección de aorta proximal.', 'Infarto agudo de miocardio complicado con rotura de músculo papilar.', 'Tromboembolismo pulmonar masivo.', 'Pericarditis efusivo-constrictiva.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 104, 'Sin clasificar', 'Hombre de 71 años portador de un marcapasos bicameral por bloqueo AV completo. Está en ritmo sinusal a 85 lpm con ritmo ventricular estimulado por el marcapasos. La interrogación del marcapasos muestra un porcentaje de estimulación ventricular del 99%. En el ecocardiograma tiene dilatación y disfunción sistólica de ambos ventrículos. La fracción de eyección del ventrículo izquierdo es del 30% y tiene insuficiencia mitral funcional grave. No tiene lesiones obstructivas en la coronariografía. Está en clase funcional III NYHA a pesar de tratamiento médico óptimo para la insuficiencia cardíaca con fracción de eyección reducida. ¿Cuál de las siguientes es la primera opción de tratamiento?:', 'Cirugía de reparación valvular.', 'Cirugía de sustitución valvular.', 'Terapia de resincronización cardíaca.', 'Mitra-Clip.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 105, 'Sin clasificar', 'Neonato de 10 días de vida que es traído por sus padres a los servicios de urgencias por presentar, desde hace 24 horas, rechazo de las tomas e hipotonía generalizada. Tras pruebas complementarias, se diagnostica de coartación de aorta preductal crítica. El paciente evoluciona en pocas horas hacia el shock cardiogénico. En este contexto, ¿cuál debe ser el primer tratamiento para mejorar la hemodinámica de este paciente?', 'Iniciar perfusión continua con prostaglandinas E1.', 'Administrar tratamiento con ibuprofeno.', 'Plantear cirugía de carácter emergente.', 'Realizar cateterismo y atrioseptostomía de Rashking urgente.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 106, 'Sin clasificar', 'Mujer de 46 años que tras 10 años de mastectomía derecha con vaciamiento ganglionar seguida de quimioterapia y radioterapia presenta linfedema de brazo derecho de larga evolución con importante edema y empastamiento, sin signos de celulitis. ¿Cuál de las siguientes medidas terapéuticas NO está recomendada?', 'Realización de actividad física con elevación del miembro superior derecho.', 'Terapia física con fisioterapia descongestiva.', 'Diuréticos para reducir edema.', 'Liposucción.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 107, 'Sin clasificar', 'En un paciente que tras una embolectomía por isquemia arterial aguda secundaria a un émbolo en la bifurcación aorto-ilíaca, presenta hipotensión, hipercalciuria, mioglobinuria e insuficiencia renal, ¿cuál de entre los siguientes es el diagnóstico más probable?', 'Trombosis arterial recurrente.', 'Síndrome de reperfusión.', 'Necrosis muscular.', 'Neuropatía isquémica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 108, 'Sin clasificar', 'Hombre de 55 años con HTA y dislipemia que consulta por disnea de esfuerzo. Presenta en la ecocardiografía válvula aórtica bicúspide con área valvular aórtica de 0,9 cm2, gradiente transvalvular de 45 mmHg, velocidad pico de 5,5 m/seg, raíz aórtica de 6 cm y fracción de eyección de ventrículo izquierdo de 45%. En la analítica, péptido natriurético tipo B el triple de lo normal. ¿Qué opción terapéutica le recomendaría?:', 'Seguimiento por médico de atención primaria mientras esté asintomático.', 'Implante de una prótesis valvular aórtica biológica transcatéter (TAVI).', 'Valvuloplastia aórtica.', 'Cirugía de sustitución valvular aórtica y raíz.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 109, 'Sin clasificar', 'En la respuesta inmune innata, las células más numerosas a nivel pulmonar, que conforman la primera línea defensiva, son:', 'Neutrófilos.', 'Macrófagos.', 'Eosinófilos.', 'Mastocitos.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 110, 'Sin clasificar', 'Hombre de 60 años que acude a consulta por presentar tos y expectoración habitual mucosa, amarillenta, con más de 4-5 episodios de reagudizaciones al año, algunas veces con hemoptisis. ¿Cuál de los siguientes es el diagnóstico más probable?', 'Asma.', 'Fibrosis pulmonar idiopática.', 'Bronquiectasias.', 'Insuficiencia cardíaca. Página: 1', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 111, 'Sin clasificar', '¿Qué hallazgos de los descritos a continuación son MENOS probables en la exploración física de un paciente con fibrosis a nivel del intersticio pulmonar?:', 'Sibilancias bilaterales en la auscultación pulmonar.', 'Crepitantes teleinspiratorios bibasales.', 'Disminución del murmullo vesicular con acropaquia.', 'Vibraciones vocales disminuidas con crepitantes tipo velcro, de carácter "seco".', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 112, 'Sin clasificar', 'Paciente que en revisión en consulta refiere tos matutina diaria y disnea de moderados esfuerzos (MRC 2) habitual que limita sus actividades cotidianas en tratamiento con doble terapia broncodilatadora desde hace dos años. La espirometría presenta un FEV1 del 35% del teórico en situación basal con una respuesta broncodilatadora que muestra un incremento del FEV1 de 250 mL y un 13%. En el estudio por TC se identifican áreas de enfisema centroacinar y en la analítica 250 eosinófilos/µL. En el último año ha sufrido dos exacerbaciones respiratorias de las cuales una ha requerido ingreso hospitalario. Indique el tratamiento más adecuado:', 'Broncodilatador β-agonista de acción prolongada + broncodilatador antagonista muscarínico de acción prolongada + corticoide sistémico.', 'Añadir roflumilast a la terapia combinada.', 'Broncodilatador β-agonista de acción prolongada + broncodilatador antagonista muscarínico de acción prolongada + corticoide inhalado.', 'Broncodilatador β-agonista de acción prolongada + corticoide inhalado.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 114, 'Sin clasificar', 'En el estudio de las enfermedades intersticiales difusas del pulmón, señale en que entidad el lavado broncoalveolar posee valor diagnóstico:', 'Sarcoidosis.', 'Fibrosis pulmonar idiopática.', 'Neumonitis por hipersensibilidad.', 'Proteinosis alveolar.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 115, 'Sin clasificar', 'Hombre de 65 años, exfumador, en el que de forma incidental se identifica un nódulo pulmonar solitario (NPS) en radiografía simple de tórax. Diagnosticado de enfermedad pulmonar obstructiva crónica con un FEV1 del 30%. En el estudio por TC se describe un NPS en lóbulo superior derecho de 9 mm de diámetro con cola pleural y calcificaciones excéntricas. Se realiza tomografía por emisión de positrones con captación patológica indicativa de malignidad. ¿Cuál de las siguientes actitudes terapéuticas es la más adecuada?:', 'Es imprescindible la realización de una biopsia por cirugía torácica ante la elevada posibilidad de malignidad.', 'Al tratarse de un NPS de pequeño tamaño (< 1 cm) la actitud más adecuada es la de seguimiento radiológico estrecho con TC al mes y a los 3, 6 y 12 meses.', 'Ante la alta probabilidad de malignidad se recomienda realizar una prueba de esfuerzo cardiopulmonar y si el consumo máximo de oxígeno es <10 mL/kg/min remitir a cirugía torácica para resección.', 'Se debe realizar una prueba de esfuerzo cardiopulmonar y si el consumo máximo de oxígeno es <10 mL/kg/min el manejo terapéutico más seguro es por medio de radioterapia estereotáxica fraccionada.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 116, 'Sin clasificar', 'En una mujer de 72 años con litiasis biliar asintomática se indicaría colecistectomía laparoscópica en caso de:', 'Microlitiasis por alto riesgo de pancreatitis aguda.', 'Litiasis biliar de más de 2,5 cm de diámetro.', 'Vesícula con paredes calcificadas en porcelana.', 'Presencia de cálculos de bilirrubina.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 117, 'Sin clasificar', '¿En cuál de las siguientes técnicas quirúrgicas para la reparación de una hernia inguinal NO se emplea una malla protésica?', 'Shouldice.', 'Lichtenstein.', 'Reparación laparoscópica TEP (totalmente extraperitoneal).', 'Reparación laparoscópica TAPP (transabdominal preperitoneal). Página: 1', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 118, 'Sin clasificar', 'Mujer de 42 años que consulta por dolor rectal descrito como una sensación de peso u ocupación continua que se agrava con la deposición. En la exploración física el ano es normal y en el tacto rectal se palpa el músculo puborrectal hipertónico y doloroso a la tracción. ¿Cuál de los siguientes es el diagnóstico más probable?', 'Úlcera solitaria de recto.', 'Proctalgia fugax.', 'Proctalgia inespecífica.', 'Síndrome del elevador del ano.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 119, 'Sin clasificar', 'Un hombre con diagnóstico de melanoma avanzado y en tratamiento con nivolumab (fármaco anti-PD-1) desarrolla elevación de las transaminasas siete veces los valores normales, junto con elevación de la bilirrubina total (2,3 mg/dL). Se han descartado cuadros infecciosos y no ha mejorado tras suspender el fármaco. ¿Cuál de las siguientes afirmaciones es cierta?', 'Es una hepatitis inmunomediada por nivolumab y es indistinguible de una hepatitis autoinmune.', 'La reintroducción del fármaco una vez resuelta conlleva la reaparición del cuadro en la mayoría de los casos.', 'Los corticoides a dosis de 1 mg/kg de prednisona o equivalente son el tratamiento de elección en esta situación.', 'La aparición de esta entidad es tardía, generalmente meses después de iniciado el tratamiento.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 120, 'Sin clasificar', 'Un paciente con enfermedad de Crohn con antecedente de extirpación de un melanoma precisa iniciar un tratamiento avanzado por corticodependencia. ¿Cuál de los siguientes fármacos se debería evitar al estar descrito un aumento del riesgo de dicha neoplasia?', 'Azatioprina.', 'Infliximab.', 'Vedolizumab.', 'Ustekinumab.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 121, 'Sin clasificar', 'Respecto al divertículo faringoesofágico o divertículo de Zenker, es cierto que:', 'Es un divertículo por tracción y consta de todas las capas de la pared esofágica.', 'Es menos frecuente que los divertículos del tercio medio del esófago en la actualidad.', 'No se trata con miotomía del cricofaríngeo si el tamaño es igual o menor a 2 cm.', 'Cuando se interviene mediante abordaje abierto para practicar una diverticulectomía o una divertículopexia, la incisión se realiza en el lado izquierdo del cuello.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 122, 'Sin clasificar', 'Mujer de 67 años con antecedentes de infección por VHC que acude a urgencias por hematemesis. A la exploración observamos ascitis y ligera ictericia. ¿Cuál es la actitud diagnóstica y terapéutica más adecuada?', 'Estabilizar hemodinámicamente, hacer una endoscopia y colocar un TIPS si tiene hemorragia por varices.', 'Realizar una paracentesis, seguido de una endoscopia y ligadura de varices.', 'Estabilizar al paciente, iniciar un fármaco vasoactivo, realizar una endoscopia y practicar una ligadura si hay hemorragia por varices.', 'Esperar al resultado de la endoscopia para actuar en consecuencia.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 123, 'Sin clasificar', 'Mujer de 38 años que presenta nódulo tiroideo indoloro y creciente en el lóbulo derecho de 6 meses de evolución. Ha experimentado recientemente disfagia y cambios de la voz. Se diagnostica de carcinoma medular de tiroides en estadio III con extensión extratiroidea y compromiso de ganglios linfáticos cervicales. De entre los siguientes, ¿cuál es el tratamiento más adecuado?:', 'Tiroidectomía subtotal.', 'Hemitiroidectomía derecha.', 'Tiroidectomía total con extirpación de ganglios linfáticos cervicales.', 'Quimioterapia exclusiva.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 124, 'Sin clasificar', 'Mujer de 58 años que consulta por presentar desde hace varios meses dolor abdominal epigástrico intermitente, náuseas y pérdida de peso involuntaria de 8 kg. Refiere episodios ocasionales de vómitos biliosos, sin haber notado sangre en los vómitos ni en las heces. Ha estado tomando antiácidos sin mucho alivio. En la exploración física se aprecia abdomen blando, con dolor a la palpación profunda en el epigastrio, sin masas palpables ni signos de peritonitis. Los análisis muestran anemia microcítica e hipocrómica y ferropenia. En la gastroscopia lesión ulcerada en la segunda porción del duodeno, que se biopsia. El informe histológico confirma la presencia de adenocarcinoma duodenal. Una TC abdominal muestra la lesión limitada al duodeno, sin evidencia de diseminación a ganglios linfáticos o metástasis a distancia. ¿Cuál es el siguiente paso más adecuado en el manejo de esta paciente?', 'Observación y seguimiento periódico con endoscopia digestiva alta debido a la localización del tumor.', 'Quimioterapia neoadyuvante seguida de una nueva evaluación para posible resección quirúrgica.', 'Duodenopancreatectomía cefálica (procedimiento de Whipple) como tratamiento de elección.', 'Radioterapia dirigida al duodeno para controlar la enfermedad local antes de considerar la cirugía. Página: 1', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 125, 'Sin clasificar', 'Mujer de 60 años que tras un esfuerzo refiere la aparición de una tumoración en la zona inguinocrural derecha no reductible y muy dolorosa. Acude a urgencias con un cuadro de vómitos con dolor y distensión abdominal. ¿Cuál es el diagnóstico más probable?', 'Hernia inguinal directa.', 'Hernia inguinal indirecta.', 'Hernia obturatriz.', 'Hernia crural.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 126, 'Sin clasificar', 'Hombre de 77 años que acude a urgencias por prurito, ictericia y síndrome tóxico de un mes de evolución. Refiere ingesta de amoxicilinaclavulánico desde hace 10 días por un resfriado. A su llegada se realiza una ecografía que se informa de dilatación de la vía biliar intra y extrahepática con vesícula biliar distendida. ¿Cuál es la sospecha diagnóstica y la actitud a seguir?:', 'Colecistitis aguda e indicación de colecistectomía urgente.', 'Coledocolitiasis distal y solicitud de colangiorresonancia magnética.', 'Toxicidad por fármacos y suspensión de la medicación.', 'Tumoración maligna obstructiva de colédoco distal y solicitar TC abdominal.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 127, 'Sin clasificar', 'La forma más eficaz de evaluación preoperatoria de la función del cuerpo esofágico y del esfínter esofágico inferior en un paciente con sospecha de reflujo gastroesofágico es:', 'La monitorización ambulatoria del pH y la impedancia.', 'Manometría esofágica.', 'Esofagoduodenoscopia.', 'Esofagograma con bario.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 128, 'Sin clasificar', 'Mujer de 34 años con diagnóstico de púrpura trombocitopénica idiopática (PTI) refractaria al tratamiento médico remitida para evaluación quirúrgica. A pesar del tratamiento con corticosteroides y otros inmunosupresores, sus recuentos plaquetarios han permanecido bajos, con episodios recurrentes de sangrado leve. Se decide realizar una esplenectomía laparoscópica como siguiente paso terapéutico. En relación con la planificación y manejo de la esplenectomía laparoscópica, ¿cuál de las siguientes estrategias es la más adecuada?:', 'La ligadura temprana de la arteria esplénica es crucial para reducir el riesgo de sangrado intraoperatorio y debe realizarse antes de movilizar el bazo en todos los casos.', 'La preservación del polo inferior del bazo es recomendable en pacientes con PTI para mantener una función inmunológica parcial.', 'El abordaje lateral izquierdo es la única opción en esplenectomías laparoscópicas y debe emplearse independientemente del tamaño del bazo.', 'La vacunación preoperatoria contra neumococo, meningococo y Haemophilus influenzae es esencial para reducir el riesgo de infección postesplenectomía y debe completarse al menos dos semanas antes de la cirugía, siempre que sea posible.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 129, 'Sin clasificar', '¿Cuál de las siguientes medidas aconsejadas para reducir la infección de la herida quirúrgica es INCORRECTA?:', 'En caso de ser necesario eliminar el vello, está indicado rasurarlo con cortadora eléctrica o con cuchilla.', 'Es recomendable mantener la temperatura corporal del paciente >35,5ºC.', 'Es recomendable mantener la glucemia en cifras <180 mg/dL.', 'El intervalo de inicio de la infusión del antibiótico hasta la realización de la incisión debe ser menor de 60 minutos.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 130, 'Sin clasificar', 'En un paciente diagnosticado de fracaso renal agudo, el tratamiento con hemodiálisis está indicado en todas las siguientes situaciones clínicas, EXCEPTO en una:', 'Acidosis metabólica que no responde a tratamiento con bicarbonato.', 'Sobrecarga de volumen con edema agudo de pulmón.', 'Hiperpotasemia refractaria a tratamiento médico.', 'Proteinuria de 1 gramo en la orina de 24 horas. Página: 2', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 131, 'Sin clasificar', 'Mujer de 54 años diagnosticada de diabetes mellitus tipo 2 hace tres años en tratamiento con metformina y lisinopril con buen control metabólico. Es enviada a consulta de Nefrología por creatinina sérica de 1,7 mg/dL, filtrado glomerular estimado de 49 mL/min/1,73m2 y cociente albumina/creatinina en orina de 250 mg/g. En los siguientes meses se confirma estabilidad de la función renal, las cifras de presión arterial se mantienen alrededor de 125/70 mmHg, en la ecografía se observan riñones de tamaño y morfología normal y en el estudio de fondo de ojo se objetiva una retinopatía diabética grado 2. ¿Cuál de las siguientes es la actitud a seguir?:', 'No hacer modificaciones en el tratamiento dada la estabilidad y buen control de su enfermedad.', 'Añadir un antagonista del receptor de la angiotensina II para lograr un mejor control de la presión arterial y disminuir la albuminuria.', 'Indicar la realización de una biopsia renal para confirmar la existencia de una enfermedad renal diabética.', 'Iniciar tratamiento con un inhibidor del cotransportador de sodio-glucosa tipo 2 que promueve la excreción urinaria de glucosa y tiene un efecto nefroprotector.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 132, 'Sin clasificar', 'El síndrome de secreción inadecuada de hormona antidiurética (SIADH), se caracteriza por:', 'Hiponatremia con osmolalidad sérica baja y osmolalidad urinaria elevada.', 'Hiponatremia hipovolémica con concentración urinaria de sodio y osmolalidad en orina elevadas.', 'Su tratamiento se basa en la restricción hídrica y la administración de fármacos agonistas del receptor de vasopresina.', 'En la mayoría de los casos se asocia con la administración de fármacos, especialmente antibióticos e inmunosupresores.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 133, 'Sin clasificar', 'Hombre de 37 años que se deriva a consulta de Nefrología para estudio de hematuria microscópica persistente. La exploración es normal salvo por presión arterial 160/100 mmHg. Hemograma sin alteraciones, urea 25 mg/dL, creatinina 0,8 mg/dL, Na 139 mEq/L, K 4,5 mEq/L, perfil hepático y lipídico normales, no hipoalbuminemia ni hipoproteinemia; estudio de autoinmunidad normal, complemento, inmunoglubulinas y proteinograma normales; serología vírica negativa; proteinuria de 0,75 g/24h; sedimento urinario con 30 eritrocitos por campo, 90% dismórficos, no leucocituria. Se realiza biopsia renal que muestra depósitos mesangiales de IgA, IgG y C3 con hipercelularidad mesangial (M1) y glomeruloesclerosis segmentaria (S1) pero sin proliferación endocapilar (E0) ni fibrosis túbulo-intersticial (T0) ni presencia de semilunas. ¿En este momento, cuál de entre los siguientes es el tratamiento más recomendado?:', 'Monoterapia con corticoides a 0,5 mg/kg/día con pauta descendente en 3 meses.', 'Control de la presión arterial y la proteinuria (añadir un antagonista de los receptores de angiotensina II).', 'Rituximab como primera opción y, si no hay respuesta, administrar ciclofosfamida.', 'Corticoides a altas dosis junto con ciclofosfamida como tratamiento de inducción.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 134, 'Sin clasificar', 'Hombre de 65 años que presenta un episodio de infección respiratoria y es tratado con amoxicilina/clavulánico. Una semana después comienza con fiebre y aparición de rash cutáneo por lo que acude a Urgencias. En la analítica se objetiva deterioro de función renal con creatinina sérica 3,2 mg/dL (previa 1,2 mg/dL), eosinofilia y presencia de proteinuria y microhematuria en el sistemático de orina. Indique cuál de estas actitudes es la más correcta:', 'Es necesario realizar una biopsia cutánea para establecer el diagnóstico.', 'Hay que aumentar la dosis de antibiótico pues probablemente se trate de una nefropatía tubulointersticial aguda de etiología infecciosa.', 'Se debe suspender el antibiótico y plantear tratamiento con esteroides si la función renal no mejora en 2-3 días.', 'Hay que iniciar tratamiento con bolus de esteroides a dosis altas y realizar una biopsia renal. Página: 2', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 135, 'Sin clasificar', 'Hombre de 72 años, remitido a consulta tras un hallazgo en una TC solicitada para el estudio de molestias digestivas inespecíficas. Se objetiva una lesión sólida, exofítica, heterogénea, con realce intenso tras la administración de contraste, de 4,9 cm de diámetro, dependiente del polo inferior renal derecho; en el riñón izquierdo litiasis piélica de 3 cm que condiciona hidronefrosis y atrofia cortical. Antecedentes personales de hipertensión, sobrepeso (mide 1,6 m y pesa 95 kg) y fumador habitual. En la analítica destaca creatinina sérica de 1,5 mg/dL. Señale de entre las siguientes opciones de tratamiento la que considera más adecuada:', 'Nefrectomía bilateral, con suprarrenalectomía derecha y linfadenectomía retroperitoneal.', 'Nefrectomía parcial derecha.', 'Biopsia percutánea. Quimioterapia neoadyuvante y nefrectomía radical derecha.', 'Nefrectomía radical derecha. Inmunoterapia adyuvante.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 136, 'Sin clasificar', 'Hombre de 53 años acude a urgencias por anuria de 48 horas de evolución. Presenta dolor abdominal difuso de varios días de evolución que no se modifica con la posición ni con la ingesta. No ha presentado fiebre pero sí náuseas con dos vómitos escasos biliosos sin productos patológicos, además de estreñimiento. En la analítica sanguínea presenta ligera leucocitosis con desviación izquierda, creatinina 7 mg/dL con FG<15mL/min, sodio 132 mmol/L y potasio 5,7 mmol/L, bilirrubina 1 mg/dL, amilasa 100 U/L, AST 30 U/L, ALT 45 U/L, fosfatasa alcalina 60 U/L, y GGT 70 U/L. En el sedimento de orina únicamente se evidencian 5-10 hematíes/campo y leve piuria. En la ecografía abdominal dilatación pielocalicial y ureteral moderada-severa bilateral con leve disminución del parénquima en el riñón izquierdo y múltiples imágenes hiperecoicas con sombra acústica posterior en todos los grupos caliciales así como en el uréter proximal izquierdo. ¿Cuál es la actitud más correcta a seguir?:', 'Analgesia iv y sueroterapia intensiva para forzar diuresis.', 'Diuréticos intravenosos.', 'Derivación de la vía urinaria de forma bilateral.', 'Solicitar TC ante la sospecha de abdomen agudo.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 137, 'Sin clasificar', 'Hombre de 28 años que consulta por haberse despertado por dolor en la región genital y tumefacción en el pene. No recuerda con detalle lo sucedido en las últimas 12 horas. En las últimas 48 h ha consumido alto volumen de alcohol, varias drogas (mefedrona, cocaína, anfetamina), junto con sildenafilo y se ha autoinyectado en el pene 20 µg de alprostadil. A la exploración destaca, pene flácido, glande no visible en su totalidad por edema y hematoma expansivo de partes blandas. Presenta restos hemáticos en el meato uretral. ¿Cuál de las siguientes opciones NO formaría parte de su plan terapéutico?:', 'Gasometría obtenida mediante punción del cuerpo cavernoso.', 'Revisión quirúrgica urgente.', 'Evitar el sondaje vesical.', 'Ecografía de pene.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 138, 'Sin clasificar', 'Hombre de 51 años que consulta preocupado por la aparición de leve goteo postmiccional. Tiene dislipemia, hipertensión arterial y alopecia androgénica incipiente. Sigue tratamiento con simvastatina, enalapril, minoxidil y dutasteride. Padre y hermano fallecidos por cáncer de próstata. En los reconocimientos de salud laboral realizados en 2.021 y 2.023 se observa PSA de 0,3 y de 3,8 ng/mL respectivamente (valores de referencia <4 ng/mL). Una RMN prostática multiparamétrica muestra una próstata de 55 mL y en secuencia T2 un nódulo hipointenso moderado y homogéneo de 1,7 cm, con restricción de la difusión y realce precoz en perfusión en el límite entre el estroma fibromuscular anterior y la zona transicional del lóbulo izquierdo prostático. Repetimos una nueva determinación de PSA 3,5 ng/mL. A la vista de estos hallazgos, ¿qué recomendación propondría al paciente como la más adecuada?:', 'Biopsia prostática transrectal sistemática.', 'Iniciar un tratamiento antibiótico empírico durante 10 días y realizar una biopsia prostática sistemática al finalizar.', 'Tranquilizar al paciente, ofrecer tratamiento sintomático alfa-bloqueante y seguimiento.', 'Biopsia prostática transperineal sistemática y dirigida mediante fusión de imágenes RMN.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 139, 'Sin clasificar', '¿Cuál de estas afirmaciones es cierta sobre los subtipos moleculares de cáncer de mama?:', 'El cáncer de mama triple negativo es el subtipo más frecuente.', 'El cáncer de mama HER2+ es el subtipo menos agresivo.', 'El cáncer de mama luminal A es el subtipo más raro.', 'El cáncer de mama triple negativo es el subtipo más agresivo. Página: 2', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 140, 'Sin clasificar', 'Mujer de 60 años con diagnóstico reciente de cáncer de mama metastásico con alta carga tumoral. Acude a Urgencias 48 horas después de haber recibido el primer ciclo de tratamiento, con cuadro de náuseas, vómitos, diarrea, dolor abdominal, astenia intensa y letargia. En la analítica sanguínea presenta alteración de la función renal. ¿Cuál de las siguientes alteraciones analíticas esperaría encontrar también?:', 'Hipouricemia.', 'Hiperpotasemia.', 'Hipofosfatemia.', 'Hipercalcemia.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 141, 'Sin clasificar', '¿A cuál de las siguientes proteínas presentes en la superficie celular se une el fármaco pembrolizumab?:', 'PD-1.', 'PD-L1.', 'CTLA-4.', 'HER2.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 142, 'Sin clasificar', '¿Cuál de estos pacientes en tratamiento con quimioterapia cumple criterios de neutropenia febril?:', 'Mujer de 38 años intervenida de cáncer de mama en curso de quimioterapia adyuvante que acude a urgencias por temperatura de 38,5ºC, odinofagia, rinorrea y buen estado general. Neutrófilos 400/mm3.', 'Mujer de 68 años intervenida de cáncer de colon estadio IV en curso de quimioterapia de primera línea que acude a urgencias por temperatura de 37,8ºC, diarrea y mucositis grado 2. Hemodinamicamente estable. Neutrófilos 300/mm3.', 'Hombre de 50 años intervenido de adenocarcinoma gástrico en curso de quimioterapia adyuvante que acude a urgencias por escalofríos y temperatura de 37,5ºC sin otra sintomatología acompañante. Neutrófilos 600/mm3.', 'Hombre de 65 años afecto de adenocarcinoma gástrico metastásico en curso de quimioterapia de segunda línea con ECOG 1 que acude a urgencias por temperatura de 38,6 ºC y diarrea grado 1. Neutrófilos 700/mm3.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 143, 'Sin clasificar', 'En un paciente con cáncer colorrectal metastásico irresecable RAS nativo y con pérdida de expresión de proteínas reparadoras del ADN (MSI-H). ¿Cuál debe ser el tratamiento de elección de primera línea?:', 'Quimioterapia + Anti-EGFR.', 'Inmunoterapia.', 'Quimioterapia.', 'Quimioterapia + Anti-VEGFR.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 144, 'Sin clasificar', 'Hombre de 48 años, exfumador hasta el 2.020, con antecedente de nefrectomía parcial izquierda en el 2.020 por carcinoma de células renales, tipo célula clara, grado 2/4, pT1b, que acude por autopalparse una adenopatía laterocervical alta hace 4 meses. En la ecografía de cuello se identifican 2 lesiones nodulares submaxilares y en el TC de cuello se informa de una lesión nodular de partes blandas derecha que corresponde probablemente a una adenopatía sospechosa. Se indica biopsia de la lesión donde se observa una proliferación neoplásica constituida por células con marcada atipia citológica que se disponen con un patrón de crecimiento difuso. El estudio inmunohistoquímico es positivo para CD20, y negativo para CD3, CD30, CD15 y CKAE1-AE3. En estos casos se completa el estudio con CD10, Bcl6 y MUM1 para indicar el fenotipo de la neoplasia. ¿Cuál es el diagnóstico anatomopatológico?:', 'Linfoma Hodgkin variante clásica.', 'Linfoma B difuso de célula grande.', 'Linfoma T periférico.', 'Metástasis de carcinoma.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 145, 'Sin clasificar', 'Hombre de 17 años con hemofilia A grave e inhibidor de alto título frente al FVIII que presenta sangrado agudo a nivel articular. ¿Cuál de los siguientes tratamientos es el más indicado para controlar la hemorragia?', 'Desmopresina.', 'Emicizumab.', 'Ácido tranexámico.', 'Factor VII activado recombinante.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 146, 'Sin clasificar', 'Hombre de 76 años que es intervenido por recambio protésico de cadera derecha tras traumatismo. Entre los antecedentes personales destaca hipertensión arterial en tratamiento fármacológico y recambio protésico de rodilla izquierda hace 3 meses por artrosis evolucionada. Al cuarto día del postoperatorio se detecta trombopenia de 52.000/mm3 con cifras de hemoglobina y leucocitos normales. El estudio de coagulación y la bioquímica es normal. ¿Cuál es el diagnóstico más probable?:', 'Púrpura trombótica trombocitopénica.', 'Coagulación intravascular diseminada.', 'Trombopenia inducida por heparina.', 'Síndrome hemolítico urémico.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 147, 'Sin clasificar', 'Los siguientes tipos de linfoma pueden ser originados por virus. ¿Cuál de ellos es producido por el virus herpes humano tipo 8 (KSHV/HHV8)?', 'Leucemia-linfoma T del adulto.', 'Linfoma primario de cavidades.', 'Linfoma de Burkitt.', 'Granulomatosis linfomatoide. Página: 2', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 148, 'Sin clasificar', 'Mujer de 50 años diagnosticada de síndrome mielodisplásico con monosomía del cromosoma 7 (45 XX -7 [20]) es sometida a un trasplante hematopoyético alogénico con sangre de cordón umbilical de un hombre compatible procedente de un banco de otro país. A los tres meses del trasplante con recuperación completa de las cifras hematológicas periféricas se realiza una punción de médula ósea, que no presenta alteraciones morfológicas y un estudio cromosómico con un cariotipo 47 XXY [20]. ¿Cuál es la explicación de estos hallazgos?:', 'El donante tiene un síndrome de Klinefelter no diagnosticado.', 'En la médula ósea coexisten células del donante y del receptor (quimerismo mixto).', 'Tras el trasplante ha existido un fenómeno de fusión celular entre las células del donante y receptor que ha originado el nuevo cariotipo.', 'En el cariotipo realizado precozmente tras un trasplante hematopoyético es habitual encontrar alteraciones cromosómicas transitorias de este tipo que carecen de significación clínica.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 149, 'Sin clasificar', 'Mujer de 90 años sin alergias medicamentosas conocidas, con HTA y gonalgia nocturna por gonartrosis derecha de intensidad leve-moderada de tres meses de evolución. Refiere que no toma ninguna medicación y se confirma que realiza las medidas higiénicas del sueño correctamente. Consulta a su médico de atención primaria por insomnio de conciliación y mantenimiento que le interfiere con sus actividades diarias. ¿Qué fármaco es más adecuado iniciar en este caso?:', 'Paracetamol.', 'Diazepam.', 'Mirtazapina.', 'Trazodona.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 150, 'Sin clasificar', 'En los pacientes mayores con síndrome de inmovilidad una de las siguientes manifestaciones clínicas o consecuencias NO es atribuible al mismo:', 'Déficit intelectual.', 'Aumento de la frecuencia cardíaca.', 'Reducción de la sensibilidad a la insulina.', 'Balance nitrogenado positivo.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 151, 'Sin clasificar', 'Hombre de 85 años diagnosticado de enfermedad de Alzheimer en tratamiento con donepezilo. Desde hace una semana y coincidiendo con una infección urinaria por germen sensible a amoxicilina/clavulánico, presenta un trastorno grave de conducta; por todo ello, recibe tratamiento con dicho antibiótico y con risperidona 1 mg cada 12 horas. Hoy la familia lo trae a su consulta porque a pesar de mejorar la infección de orina, está muy enlentecido, necesitando ayuda para comer y vestirse, no es capaz de deambular sin ayuda, duerme de día y presenta insomnio de madrugada. Ante esta situación clínica señale la respuesta CORRECTA:', 'Probablemente se trata de un efecto secundario de la risperidona, por lo que se debe retirar.', 'Se debe tratar el insomnio de madrugada añadiendo benzodiacepinas.', 'Hay que esperar a que se resuelva totalmente la infección urinaria para cambiar la medicación actual.', 'Ha empeorado la demencia y se debe añadir memantina al tratamiento de base con donepezilo.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 152, 'Sin clasificar', 'Los criterios STOPP/START tienen el objetivo de optimizar la medicación y minimizar las reacciones adversas a los medicamentos durante la revisión de la medicación en adultos mayores. En cuanto a los criterios START (versión 3, última versión), ¿cuál deberíamos valorar indicar?:', 'Estrógenos tópicos vaginales en la vaginitis atrófica sintomática.', 'Vacuna antitetánica ante una herida abierta.', 'Parche de lidocaína tópica para el dolor articular generalizado.', 'Corticoesteroides inhalados en el EPOC estadio GOLD 1-2.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 153, 'Sin clasificar', 'En la actualidad se definen varios estadios o etapas de la diabetes tipo 1 autoinmune. Señale cuál es la definición CORRECTA:', 'El estadio o etapa 3 se caracteriza por la autoinmunidad y tolerancia alterada de la glucosa (ya sea basal o tras test de sobrecarga con glucosa oral).', 'El estadio o etapa 1 se caracteriza por presencia única de autoinmunidad contra las células de los islotes sin aparición de alteraciones de la glucosa.', 'El estadio o etapa 2 se caracteriza por hiperglucemia con cifras que definen diabetes.', 'La luna de miel aparece en el estadio 2, con la hiperglucemia. Página: 2', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 154, 'Sin clasificar', 'Mujer que acude a consulta de endocrino por secreción láctea por el pezón y una cifra de prolactina en sangre de 45 µg/L (normal <20 µg/L). ¿Cuál es la actitud diagnóstica más apropiada?:', 'La primera medida a realizar es una resonancia cerebral porque lo más probable es que sea un macroadenoma secretor de prolactina.', 'Se debe interrogar sobre la toma de fármacos antagonistas del receptor de dopamina o un posible embarazo.', 'Las pruebas de laboratorio para su correcta caracterización consisten en la medición aislada de prolactina.', 'Se debe descartar un hipertiroidismo primario.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 155, 'Sin clasificar', 'La estrategia de cribado de diabetes gestacional en un solo paso consiste en:', 'Test de sobrecarga oral de glucosa con 50 gr de glucosa.', 'Test de sobrecarga oral de glucosa con 75 gr de glucosa.', 'Test de sobrecarga oral de glucosa con 90 gr de glucosa.', 'Test de sobrecarga oral de glucosa con 100 gr de glucosa.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 156, 'Sin clasificar', 'Está de guardia en urgencias y valora a un hombre de 45 años que consulta por vómitos de 2-3 días de evolución con disconfort abdominal y astenia intensa desde hace 1 mes. La presión arterial en triaje es 85/40 mmHg. Cuando lo explora objetiva hiperpigmentación parcheada en la cavidad oral y en la analítica destaca sodio de 134 mEq/L. ¿Cuál es su primera opción diagnóstica de las expuestas a continuación?:', 'Hemocromatosis.', 'Síndrome de Peutz Jeghers.', 'Enfermedad de Addison.', 'Síndrome Stevens-Johnson.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 157, 'Sin clasificar', '¿Qué fármaco de los mencionados a continuación ha de tenerse en cuenta cuando se evalúa a un paciente con hiperparatiroidismo?:', 'Hidroclorotiazida.', 'Losartán.', 'Amlodipino.', 'Doxazosina.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 158, 'Sin clasificar', '¿Cuál de las siguientes causas de hipertiroidismo puede cursar con TSH normal o elevada?:', 'Tirotoxicosis facticia.', 'Struma ovarii.', 'Adenoma hipofisario productor de TSH.', 'Hipertiroidismo por beta-HCG durante la gestación.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 159, 'Sin clasificar', 'Hombre de 58 años, fumador de 30 cigarrillos diarios desde los 19 años, con antecedentes de hipertensión arterial mal controlada, diabetes mellitus tipo 2 y obesidad grado I. En estudio por disnea de 5 meses de evolución, asociando pérdida de peso, astenia e hiporexia. Como parte del estudio se realiza TC toracoabdominal describiéndose la presencia de un nódulo pulmonar inespecífico de 1,1 cm en lóbulo superior derecho sin datos de malignidad y un nódulo en la glándula suprarrenal derecha de 1,9 cm. ¿Qué pruebas complementarias habría que solicitar para el estudio del incidentaloma suprarrenal?:', 'Test de supresión con 8 mg de dexametasona (DXM) nocturno, metanefrinas libres plasmáticas y resonancia magnética centrada en suprarrenales.', 'Metanefrinas fraccionadas en orina de 24 horas, test de supresión con 1 mg DXM nocturno, ratio renina/aldosterona y PET-TC con 18FDG.', 'Metanefrinas fraccionadas en orina de 24 horas, test de supresión con 1 mg DXM nocturno, ratio aldosterona/renina y TC centrada en adrenales.', 'Cortisol libre urinario, metanefrinas fraccionadas en muestra aislada de orina, ratio aldosterona/renina y resonancia magnética centrada en suprarrenales.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 160, 'Sin clasificar', 'Mujer de 25 años, sin enfermedades previas conocidas, que consulta por lesión en labio inferior. No es la primera vez que le sucede desde la adolescencia, siempre en la misma zona, inicia dolor y aparece una lesión vesiculosa que se autolimita en una semana aproximadamente. Respecto al abordaje de la enfermedad de esta paciente, es INCORRECTO que:', 'Si presenta más de tres episodios anuales está indicado realizar profilaxis con un antiviral como valaciclovir 500 mg cada 12 horas o 1 g al día, durante seis meses.', 'Si es una única lesión y es un cuadro leve puede no realizarse ningún tratamiento o bien realizar tratamiento tópico con fomentos de sulfato de zinc o de cobre.', 'Si existe riesgo de afectación oftálmica estaría indicado tratar con un antivírico como valaciclovir a razón de 1 g cada 8 horas durante 7 días vía oral.', 'Es necesario recomendarle una adecuada protección solar pues la exposición solar puede motivar recurrencias. Página: 2', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 161, 'Sin clasificar', 'Hombre de 50 años que presenta una erupción generalizada especialmente en el tronco. Refiere malestar general desde hace pocos días. Hoy acude porque ha tenido fiebre la noche anterior y se ha visto una mancha negra en la zona abdominal. A la exploración física, la mancha negra corresponde a una pequeña escara. El paciente es cazador y acudió recientemente a una batida. Sobre el abordaje del caso es cierto que:', 'Es una enfermedad de declaración obligatoria.', 'El tratamiento de elección es la amoxicilina, un gramo cada 8 horas durante 7 días.', 'Debe derivarse a un centro hospitalario.', 'En la mayoría de los casos, la fiebre precede al exantema y la escara.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 162, 'Sin clasificar', 'Respecto al tratamiento de la foliculitis, es correcto que:', 'El tratamiento de elección incluso en formas localizadas es la cloxacilina vía oral.', 'En caso de alergia a la penicilina, la opción más adecuada sería el ciprofloxacino oral.', 'Debe realizarse tratamiento oral en pacientes con valvulopatía reumática por el riesgo de endocarditis.', 'Es una infección fundamentalmente estreptocócica por Streptococcus pyogenes.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 163, 'Sin clasificar', 'Hombre de 62 años con antecedentes de hipertensión arterial, diabetes mellitus tipo 2 y en tratamiento con infliximab por artritis reumatoide, se presenta en urgencias con fiebre, tos seca, mialgias y disnea leve de 5 días de evolución. A la exploración física, la saturación de oxígeno es del 90% con aire ambiente. Se realiza una radiografía de tórax que muestra opacidades en vidrio deslustrado bilaterales. La PCR en frotis nasofaríngeo para SARS-CoV-2 resulta positiva. ¿Cuál de las siguientes opciones es la conducta más apropiada?:', 'Administrar plasma de convaleciente y anticoagulación profiláctica.', 'Iniciar tratamiento con antibióticos de amplio espectro y corticoides a dosis altas.', 'Monitorización ambulatoria con seguimiento telefónico y tratamiento sintomático.', 'Ingreso hospitalario para tratamiento con remdesivir y dexametasona.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 164, 'Sin clasificar', 'Hombre de 56 años, nacido en Paraguay, acude a consulta, remitido por su médico de familia, por disnea progresiva y palpitaciones. Tiene un ECG en el que se observa extrasístoles ventriculares y bloqueo completo de rama derecha. Aporta una serología por ELISA IgG positiva frente a Trypanosoma cruzy. ¿Cuál de las siguientes respuestas es INCORRECTA?:', 'Se debe realizar una prueba serológica con inmunofluorescencia para detectar IgG frente a T. cruzy.', 'La prueba de reacción en cadena de la polimerasa (PCR) tiene un valor diagnóstico limitado en esta fase de la enfermedad.', 'Debe iniciar tratamiento con benznidazol para modificar la evolución de la enfermedad.', 'Si se confirma el diagnóstico, debe estudiar a los familiares cercanos para identificar otros casos.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 165, 'Sin clasificar', 'Una mujer de 45 años con antecedentes de pleuritis hace 3 años y episodios ocasionales de poliartritis en los últimos 8 meses, fue diagnosticada de LES hace un mes tras un ingreso por fatiga y dolor torácico opresivo de esfuerzo, donde se objetivó una Hb de 5,8 g/dL y VCM de 109 fL por una anemia hemolítica autoinmune. El resto de la analítica mostró una linfopenia de 900/mm3, plaquetas en rango de normalidad, función hepática, creatinina y ionograma normales, tiempo de protrombina 85%, TTPA se muestra prolongado (ratio de 1,8). Existe hipocomplementemia C3 y C4, ANA 1/640, con Anti-DNA +. Fue dada de alta con corticoides, hidroxicloroquina y belimumab semanal subcutáneo. A las tres semanas del alta refiere sensación disneica de 48 horas de evolución sin otros síntomas acompañantes, la Hb de urgencias es de 10,2 gr/dL. ¿Cuál de las siguientes determinaciones de laboratorio deberíamos realizar en primer lugar?:', 'Dímero D.', 'Proteínas en orina.', 'NT-proBNP.', 'Test de Coombs. Página: 2', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 166, 'Sin clasificar', 'Mujer de 72 años, procedente del medio rural que acude al servicio de urgencias por un cuadro de dolor abdominal, vómitos y diarrea líquida, que posteriormente se hace sanguinolenta, de 6 días de duración. No refiere fiebre ni tratamiento antibiótico previo. Se toman muestras para hemocultivo y estudio microbiológico de las heces y se inicia tratamiento con fluidoterapia intensiva. 48 horas después se observa disminución del nivel de conciencia y la presencia de anemia (hematocrito de 25%, hemoglobina de 7,9 g/dL), trombopenia (plaquetas de 60.000/mL), creatinina de 3,2 mg/dL, hematuria y hemoglobinuria. En el estudio de sangre periférica se aprecian abundantes esquistocitos circulantes (más del 10%). Señale la respuesta INCORRECTA:', 'Debe tratar de identificar infección por E. coli, serotipo 0157:H7 y detección por PCR de toxina Shiga (Stx1 y/o Stx2) y genes relacionados.', 'Debe iniciar tratamiento antibiótico.', 'El cuadro clínico y analítico descarta la posibilidad de infección por Clostridium diffícile.', 'La plasmaféresis no es útil en esta paciente.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 167, 'Sin clasificar', 'Mujer de 54 años de edad que acude a su consulta para estudio y evaluación del riesgo vascular. Entre sus antecedentes más relevantes, destacan un infarto agudo de miocardio a los 51 y a los 53 años de edad, hipertensión arterial controlada y un perfil lipídico con tratamiento hipolipemiante de alta intensidad de: colesterol total 120 mg/dL, cHDL 60 mg/dL cLDL 50 mg/dL, TG 128 mg/dL. HB1AC de 5.2% y glucemia plasmática en ayunas normal. Nunca ha fumado. Índice de masa corporal de 23 Kg/m2. De las siguientes pruebas o determinaciones que se exponen a continuación, ¿qué es más útil para determinar el riesgo y la etiología de eventos recurrentes en esta paciente?:', 'Determinación de ApoB.', 'Determinación de ApoA.', 'Determinación de Lp(a) o lipoproteína a.', 'Determinación de proteína C reactiva.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 168, 'Sin clasificar', 'Mujer de 28 años sin enfermedades previas, recién llegada de los Estados Unidos de América, donde ha estado practicando espeleología en el valle del Ohio durante un par de semanas, presenta clínica de infección respiratoria consistente en tos, fiebre, sensación disneica y artralgias, lesiones cutáneas nodulares y dolorosas, eritematosas y calientes en la zona pretibial. ¿En qué enfermedad hay que pensar?', 'Aspergilosis pulmonar.', 'Esporotricosis.', 'Criptococosis pulmonar.', 'Histoplasmosis.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 169, 'Sin clasificar', 'Hombre de 53 años, sin antecedentes patológicos, acude al hospital por fiebre de 10 días de evolución, con intensa cefalea retroorbitaria y una importante sensación de fatiga. No refiere dolor musculoesquelético, lesiones cutáneas ni ningún otro síntoma acompañante. A lo largo de 15 días de ingreso se objetiva fiebre persistente y la aparición de discreta ictericia conjuntival. La exploración respiratoria, cardíaca, abdominal y neurológica es normal. La analítica muestra VSG 97 mm/h, PCR 24,5 mg/dL, GOT 156 U/L, GPT 148 U/L, FA 410 U/L, GGT 794 U/L, bilirrubina total 5,5 mg/dL a expensas de la bilirrubina directa, hemoglobina 11,5 g/dL, recuento leucocitario normal, plaquetas 648.000/mm3, función renal e ionograma normales, tiempo de protrombina normal pero TTPA ratio 1,8. Los anticuerpos antinucleares (ANA) son positivos a títulos 1/160. Una ecografía abdominal no muestra ninguna alteración destacable. Desde el punto de vista clínico y a la vista de los datos analíticos, ¿cuál de las siguientes enfermedades es la que se ajusta mejor con nuestro paciente?:', 'COVID-19.', 'Fiebre Q aguda.', 'Leptospirosis grave (enfermedad de Weil).', 'Colangitis esclerosante primaria.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 170, 'Sin clasificar', 'Hombre de 38 años con dependencia alcohólica grave. Ha tenido varios ingresos por pancreatitis aguda en el contexto de ingesta de alcohol e hipertrigliceridemia grave. Acude a consulta 12 meses después del último episodio de pancreatitis. No presenta clínica que sugiera insuficiencia pancreática exocrina. Niega reiteradamente ingesta de alcohol. Sigue tratamiento con estatinas y fibratos que asegura tomárselos. Aporta un análisis básico reciente de su empresa con los siguientes datos: colesterol 300 mg/dL, cHDL 42 mg/dL, TG 1102 mg/dL, cLDL no calculable por Friedewald. Colesterol no-HDL 258 mg/dL, ApoB 90 mg/dL, Lp(a) 38 nmol/L (normal <125 nmol/L). En dicho análisis hay un dato, además de la hipertrigliceridemia, que sugiere que el paciente continúa ingiriendo alcohol. Señálelo.', 'ApoB.', 'cHDL.', 'Lp(a).', 'Colesterol total. Página: 2', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 171, 'Sin clasificar', 'Respecto a las infecciones de las heridas quirúrgicas, señale la respuesta INCORRECTA:', 'Diabetes mellitus, malnutrición, obesidad e inmunosupresión son factores de riesgo del paciente para desarrollar infecciones de las heridas quirúrgicas.', 'El control intensivo perioperatorio de la glucemia es una buena práctica de prevención de las infecciones de herida quirúrgica.', 'La mayoría de las recomendaciones sobre profilaxis antibiótica en cirugía cardíaca aconsejan mantener los antibióticos al menos 48 horas tras el procedimiento quirúrgico.', 'La antibioterapia local se emplea como método de profilaxis antimicrobiana y tratamiento antibiótico, sobre todo en la sustitución de prótesis articulares infectadas.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 172, 'Sin clasificar', 'Hombre de 37 años con infección VIH ha dejado de tomar el tratamiento por razones personales hace 3 meses; estaba tomando una combinación de dos inhibidores de transcriptasa inversa y un inhibidor de la integrasa. En la evaluación llevada a cabo en este momento tiene 120 linfocitos CD4/mm3 y una carga viral de VIH-1 de 80.000 copias/mL. Estamos pendientes del estudio de resistencias. ¿Qué debemos recomendarle en este momento?:', 'Reiniciar el tratamiento con lo mismo con lo que estaba previamente.', 'Esperar a tener el resultado del estudio de resistencias para orientar el tipo de tratamiento en función de las mutaciones identificadas.', 'Prescribir a partir de ahora un régimen basado en inhibidores de proteasa por su mayor barrera genética a las resistencias.', 'Iniciar doble terapia con inhibidores de integrasa.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 173, 'Sin clasificar', 'Hombre de 55 años con antecedentes de cáncer de pulmón (estadio IV). Su madre murió a los 65 años por un episodio de broncoaspiración. Consulta por debilidad muscular en los muslos y disfagia. Exploración física: fuerza en psoas 4+/5, cuádriceps 3/5, deltoides 5/5. Presenta ptosis palpebral bilateral y no tiene diplopía. Los valores de CPK eran 900 UI/L (normal <150 UI/L) y los de aldolasa, 7 UI/L (normal <6 UI/L). Se practicó una biopsia en el músculo vasto lateral externo del muslo derecho, en la cual se objetivó variabilidad en el tamaño de fibras, aumento del tejido conectivo, imágenes de pseudodivisión celular y vacuolas ribeteadas; no se observó infiltrado inflamatorio. ¿Qué es lo más probable que le suceda al paciente?:', 'Distrofia oculofaríngea.', 'Miopatía mitocondrial.', 'Miastenia gravis.', 'Miositis con cuerpos de inclusión.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 174, 'Sin clasificar', 'Mujer de 81 años consulta por cuadro de 1 mes de duración de astenia, febrícula, pérdida de unos 4 kg de peso, cefalea hemicraneal izquierda y dolor en la zona de los hombros y de las caderas, que le dificulta los movimientos después de estar en reposo. Se palpa una zona engrosada y dolorosa en el territorio de la arteria temporal izquierda. Respecto al proceso diagnóstico de esta paciente, señale la opción INCORRECTA:', 'La vasculitis sistémica que se sospecha con mayor probabilidad es una vasculitis de gran vaso.', 'En el análisis, la normalidad de la velocidad de sedimentación globular apoya el diagnóstico de esta vasculitis.', 'Es frecuente observar afectación de la pared arterial de la aorta y sus ramas principales mediante pruebas de imagen.', 'Una biopsia de la arteria temporal que muestre un infiltrado inflamatorio en la pared arterial confirmaría el diagnóstico de arteritis de células gigantes.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 175, 'Sin clasificar', '¿Cuál de las siguientes manifestaciones clínicas es la más característica de la miopatía de la dermatomiositis?:', 'Dificultad para andar.', 'Dificultad para subir escaleras.', 'Dificultad para abrocharse los botones.', 'Dolor muscular.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 176, 'Sin clasificar', 'Mujer de 38 años que consulta por la presencia de dolor ocular, ojo rojo bilateral, hipersensibilidad a la luz y disminución de la agudeza visual. La historia clínica se completa con antecedentes de aftas bucales dolorosas y recidivantes y un diagnóstico previo de eritema nodoso hace 2 años. En la exploración oftalmológica se observa panuveitis bilateral con signos de vasculitis retiniana bilateral. Señale la respuesta correcta sobre el diagnóstico y tratamiento de la enfermedad que sospecha en esta paciente:', 'El hallazgo de HLA B*51 confirma el diagnóstico de sospecha.', 'Las úlceras bucales dejan cicatriz en la mayoría de los casos.', 'Debe instaurar tratamiento precoz e intensivo con glucocorticoides sistémicos e inmunosupresión con azatioprina.', 'La adición al tratamiento de anticuerpos monoclonales anti TNF alfa o ciclosporina no mejora el control de la uveítis. Página: 2', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 177, 'Sin clasificar', 'Mujer de 80 años que ingresa en el hospital para estudio de anemia tras ser llevada por sus hijos a urgencias por rectorragia y decaimiento físico. Clínicamente se encuentra estable. Está diagnosticada de un deterioro cognitivo, con ideación y juicio frecuentemente incoherentes y alteraciones conductuales para lo que toma risperidona. Se sospecha neoplasia maligna de colon y se plantea realizar una colonoscopia. Usted verifica que la paciente es incapaz de entender adecuadamente lo que se le explica sobre tal prueba, su naturaleza, objetivos, posibles complicaciones, o sus consecuencias diagnósticas y eventualmente terapéuticas. En tal caso, ¿cuál de las siguientes respuestas es correcta?:', 'El médico queda eximido de plantear un proceso de consentimiento informado a la paciente, y se considera suficiente su criterio como médico para que se realice la colonoscopia.', 'El médico deberá solicitar la comparecencia del Juez, para que autorice la prueba, ante la incapacidad intelectual de la enferma para decidir convenientemente por sí misma.', 'Por no tener la paciente capacidad para decidir, deben hacerlo por ella sus familiares, debiendo quedar constancia escrita en el impreso de consentimiento informado.', 'Es jurídicamente aceptable un acuerdo entre el médico y los familiares de la enferma basado en un consentimiento informado verbal para que se practique la colonoscopia.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 178, 'Sin clasificar', 'Atiende a una paciente ingresada desde hace tres semanas en la unidad de cuidados intensivos por un cuadro de shock séptico respiratorio. Su evolución durante el ingreso no ha sido favorable y todavía continúa dependiente de ventilación mecánica invasiva. En los últimos días, tras recibir la información de que probablemente precise ventilación mecánica a medio-largo plazo, durante los periodos en que la paciente ha estado despierta, ha manifestado de forma clara su deseo de no continuar utilizando el ventilador. La paciente afirma comprender las consecuencias de esta decisión. Este caso habla de:', 'Rechazo al tratamiento.', 'Limitación del esfuerzo terapéutico o adecuación de medidas de tratamiento.', 'Suicidio asistido.', 'Eutanasia.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 179, 'Sin clasificar', 'Respecto al tratamiento del dolor en cuidados paliativos, indique, de las siguientes afirmaciones, cuál es correcta:', 'En la actualidad existen comercializados diferentes fármacos opioides para el tratamiento del dolor moderado o grave en personas que reciben cuidados paliativos, superando en perfil de efectos adversos y en efectividad a la morfina y relegándola a un papel testimonial.', 'La adicción es un problema creciente en pacientes que precisan morfina en su fase final de vida y es más frecuente cuando se emplean fármacos con efecto de larga duración (metadona o morfina de liberación prolongada).', 'El fentanilo oral transmucoso tiene un perfil de acción que lo hace útil en el dolor crónico no irruptivo y de carácter crónico.', 'La metadona es un fármaco analgésico con escasa excreción renal por lo que es útil en personas con aclaramiento renal disminuido.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 181, 'Sin clasificar', 'En relación con la marca producida por el paso de la corriente eléctrica a través de la piel (también conocida como lesión electroespecífica o “marca de Jellinek”), ¿cuál de las siguientes afirmaciones es cierta?:', 'La mayor parte de las lesiones producidas por la corriente eléctrica en medio doméstico y laboral proceden de fuentes de alto voltaje.', 'Las lesiones dérmicas dependen del efecto de un aumento de la temperatura generado sobre la dermis.', 'La corriente de bajo voltaje produce lesiones profundas, mientras que la de alto voltaje da lugar a lesiones superficiales adyacentes al punto de contacto con la corriente eléctrica.', 'La marca eléctrica es diagnóstica del lugar en el que se ha producido el contacto y, por tanto, el punto de entrada de la corriente en el cuerpo. Página: 2', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 182, 'Sin clasificar', 'Hombre de 85 años con enfermedad de Alzheimer de 6 años de evolución, actualmente en estadio GDS-FAST 7c. Está institucionalizado en centro sociosanitario desde hace 1 año. En los últimos 6 meses tiene frecuentes episodios de broncoaspiración por los que ha acudido a Urgencias y han sido tratados con antibioterapia de amplio espectro con mejoría clínica. Acude nuevamente a urgencias por disnea en relación con nuevo episodio de broncoaspiración y negativa a la ingesta. ¿Cuál debe ser la actitud a seguir?:', 'Evitar ingreso. Indicar sonda nasogástrica (SNG) con el fin de prevenir nuevas broncoaspiraciones y facilitar ingesta. Antibioterapia empírica con amoxicilina-clavulánico por SNG.', 'Ingresar para colocación de gastrostomía (PEG) con el fin de evitar nuevas broncoaspiraciones y facilitar ingesta. Antibioterapia empírica con piperacilina-tazobactam iv.', 'Evitar ingreso. No está indicada la colocación de sonda para nutrición enteral. Considerar adecuación del esfuerzo terapéutico evitando antibioterapia y dando cuidados de confort.', 'Ingresar para antibioterapia empírica con piperacilina-tazobactam, pero evitar la colocación de sonda para nutrición enteral. La curación del proceso infeccioso mejorará casi siempre la ingesta.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 183, 'Sin clasificar', 'La telemonitorización domiciliaria ha demostrado beneficios en pacientes con insuficiencia cardíaca. Una mujer de 82 años con insuficiencia cardíaca y diabetes tratada con insulina está en programa de telemonitorización y remite cada semana una serie de parámetros a su médico de familia. La semana pasada presentaba presión arterial 140/85 mmHg. Glucemia capilar basal 120 mg/dL. Glucemia postprandial 2 h tras la comida 160 mg/dL. Peso 83 kg. Frecuencia cardíaca 72 lpm. Al recibir los parámetros de esta semana que se exponen a continuación, su médico decide citar a la paciente en consulta. ¿Cuál de los siguientes parámetros ha motivado dicha decisión?:', 'Presión arterial 135/82 mmHg.', 'Peso 85 Kg.', 'Glucemia capilar basal 130 mg/dL.', 'Glucemia capilar postprandial 190 mg/dL.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 184, 'Sin clasificar', 'En un paciente con diabetes y obesidad en prevención secundaria cardiovascular, tratado con metformina y iSGLT2, que presenta mal control glucémico, ¿cuál es el fármaco de elección para mejorar dicho control?:', 'Insulina.', 'Análogos del receptor del péptido similar al glucagón tipo 1 (arGLP-1).', 'Sulfonilurea.', 'Repaglinida.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 185, 'Sin clasificar', 'Mujer de 61 años con adenocarcinoma rectal avanzado. Presenta dolor neuropático con irradiación perineal y molestias urinarias en relación con masa presacra. Mejoró con tratamiento con opioides (morfina 60 mg cada 12h) pero no tolera más aumento de dosis ni fármacos adyuvantes. ¿Cuál es el tratamiento de elección?:', 'Bloqueo del plexo celiaco.', 'Bloqueo del ganglio impar.', 'Bloqueo de nervios esplácnicos.', 'Bloqueo del nervio pudendo.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 186, 'Sin clasificar', 'En una guardia de centro de salud avisan para atender a un hombre de 63 años, que ha sido sometido a bajas temperaturas, sin precisar cuánto tiempo ha estado en exposición. A su llegada, tiene una temperatura corporal de 28ºC. ¿Cuál de los siguientes hallazgos NO cabría esperar en este cuadro?:', 'Taquipnea.', 'Fibrilación ventricular.', 'Alucinaciones.', 'Pupilas mióticas.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 187, 'Sin clasificar', 'En cuanto al uso de anticonceptivos en mujeres jóvenes en las consultas de Atención Primaria, es importante tener en cuenta diversos aspectos para la prescripción. ¿Cuál de las siguientes es INCORRECTA?:', 'Se ha de ofrecer consejo contraceptivo estructurado según los criterios de elegibilidad de la Organización Mundial de la Salud (OMS), e información tanto para la prevención de embarazos no planificados, como de enfermedades de transmisión sexual (ETS).', 'Como método anticonceptivo de urgencias, las opciones recomendadas son la toma de levonorgestrel, de acetato de ulipristal o la inserción de un DIU de cobre.', 'Ante la indicación de anticonceptivos orales se recomienda el cribado rutinario de trombofilia y dislipemia y citologías de control anuales.', 'El riesgo de tromboembolia venosa con el consumo de anticonceptivos orales es bajo, siendo el riesgo menor en los de segunda generación, frente al mayor riesgo en los de tercera y cuarta generación.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 188, 'Sin clasificar', '¿Cuál de los siguientes fármacos debería evitarse en un paciente que presenta diabetes y obesidad por ser un fármaco que puede inducir aumento de peso?', 'Metformina.', 'Sitagliptina.', 'Semaglutida.', 'Pioglitazona. Página: 3', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 189, 'Sin clasificar', 'Hombre de 69 años con adenocarcinoma de páncreas avanzado que presenta como principal sintomatología dolor de características mixtas tratado desde hace 3 meses con opioides con buen control (morfina 60 mg cada 12 horas) + adyuvantes (duloxetina 60 mg/día). Asocia astenia e hiporexia graves tratadas con corticoides desde hace 2 semanas (dexametasona 8 mg/día). Acude a consulta refiriendo somnolencia intensa y alucinaciones táctiles. En la analítica presenta como datos más destacables anemia de trastornos crónicos (Hb 10,6 g/dL) y empeoramiento de la función renal (CKD-EPI 26 mL/min). ¿Cuál es el diagnóstico más probable y la actitud a seguir?:', 'Clínica neurológica por metástasis cerebrales. Realizar TC cerebral y aumentar dosis de corticoides.', 'Psicosis inducida por corticoides. Retirar corticoides.', 'Síndrome confusional agudo hipoactivo. Iniciar tratamiento con neurolépticos.', 'Neurotoxicidad por opioides. Reducir la dosis de morfina a la mitad.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 190, 'Sin clasificar', 'Hombre de 36 años sin antecedentes de interés que ingresa en observación de urgencias en espera de intervención quirúrgica por fractura de fémur a nivel diafisario por accidente de tráfico. El paciente llega algo taquicárdico 102 lpm, con gafas nasales para mantener saturación de oxígeno en torno al 96%, 20 respiraciones por minuto y presión arterial 100/60 mmHg. Se procede a ajuste de analgesia y a las 20 horas de estancia en observación indican que el paciente puede ir a quirófano pero presenta un aumento de disnea con saturación del 89% con mascarilla tipo Venturi, 28 respiraciones por minuto, taquicardia a 110 lpm, fiebre de 38ºC y se encuentra algo obnubilado. En la analítica destaca anemia y trombocitopenia. No presenta aumento de volumen en ninguna de las 2 piernas. ¿Qué prueba complementaria tiene mayor sensibilidad y especificidad para la sospecha diagnóstica de este paciente?', 'AngioTC helicoidal con contraste.', 'Gammagrafía pulmonar de perfusión.', 'Radiografía de tórax.', 'Ecocardiografía.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 191, 'Sin clasificar', 'Hombre de 72 años sin alergias medicamentosas, no fumador y con antecedentes de hipertensión, dislipemia y diabetes. En tratamiento con ácido acetilsalicílico, atorvastatina, enalapril y metformina. Acude a urgencias por agudización de lumbalgia crónica de meses de evolución. Refiere que el dolor no es irradiado, y no mejora mucho en reposo. Ha tomado varios analgésicos sin ninguna mejoría. A la exploración no presenta dolor en espinosas dorsolumbares, el signo de Lasegue es negativo, no presenta limitación a la movilidad, reflejos normales y no hay alteración de sensibilidad o fuerza. Pulsos pedios ausentes y tibiales débiles. No edemas de miembros inferiores. Ante la sospecha diagnóstica, ¿qué prueba nos daría el diagnóstico más rápidamente con mayor sensibilidad y especificidad?:', 'Ecografía abdominal.', 'TC toraco-abdominal.', 'Resonancia magnética.', 'Radiografía de columna lumbosacra.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 192, 'Sin clasificar', 'Acude a urgencias un hombre de 34 años, sin diagnósticos previos, con antecedente de consumo de drogas por vía parenteral, con fiebre, tos no productiva y disnea progresiva de varias semanas de evolución. Se realiza radiografía de tórax que muestra infiltrado intersticial bilateral. En analítica sanguínea destaca linfopenia y lactato deshidrogenasa elevada. La saturación de oxígeno es del 88% respirando aire ambiente en reposo. ¿Cuál de las siguientes aseveraciones le parece INCORRECTA?:', 'Iniciaría tratamiento de soporte, oxigenoterapia y ceftriaxona.', 'Iniciaría tratamiento con Trimetropim/sulfametoxazol, corticoides y oxigenoterapia.', 'Solicitaría serología del virus de la inmunodeficiencia humana.', 'Solicitaría estudio microbiológico de esputo.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 193, 'Sin clasificar', 'Hombre de 46 años sufre accidente de tráfico a alta velocidad con varios vuelcos del vehículo y necesidad de extricación por parte del equipo de bomberos. El paciente es trasladado en una UVI móvil al servicio de urgencias más próximo, con inmovilización en colchón de vacío. A su llegada al hospital se encuentra inestable a pesar de sueroterapia intensiva. A la exploración presenta los siguientes signos vitales: frecuencia respiratoria 35 rpm. Saturación de oxígeno 100% con mascarilla reservorio. Frecuencia cardíaca 140 lpm. Presión arterial 60/30 mm Hg. Temperatura 35,5ºC y glucemia 110 mg/dL. De las siguientes, indique la exploración o prueba complementaria clave del árbol de decisión en este paciente:', 'Hemograma y bioquímica.', 'TC abdominal.', 'e-FAST (Extended Focused Abdominal Sonography for Trauma).', 'Punción lavado peritoneal. Página: 3', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 194, 'Sin clasificar', 'En un paciente diagnosticado de una lesión tumoral ósea maligna que ha recibido tratamiento neoadyuvante, se realiza resección de la pieza y posterior biopsia para su análisis anatomopatológico. Indique, de las siguientes, ¿cuál es la información más relevante para el pronóstico del paciente?:', 'Tasa de necrosis en la pieza por efecto de terapia neoadyuvante.', 'Número de células tumorales en fase G0 de no división o interfase.', 'Porcentaje de células gigantes que se encuentran en la lesión.', 'Cantidad de células no estromales que componen el tumor.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 195, 'Sin clasificar', 'Mujer de 60 años que acude al hospital por hematuria, mal estado general y fiebre. Se orienta clínicamente de insuficiencia renal progresiva y se decide realizarle una biopsia renal donde se observa una glomerulonefitis necrotizante con reacción extracapilar (semilunas) que afecta a más del 50% de los glomérulos. La inmunofluorescencia directa es negativa. Hay un dato del laboratorio de inmunología que nos ayudará a confirmar el diagnóstico, pero ¿cuál es el diagnóstico más probable?:', 'Glomerulonefritis pauciinmune.', 'Nefritis tubulointersticial.', 'Síndrome de Goodpasture.', 'Nefropatía IgA.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 196, 'Sin clasificar', 'Niño de 3 años de edad con antecedentes de dermatitis atópica leve, sin alergias conocidas. Acude a la consulta con su madre quien comenta que en la última semana le han aparecido unas lesiones en la piel de la cara y la región glútea. Estas lesiones comenzaroncomo pequeñas máculas eritematosas que en pocos días pasaron a vesículas y erosiones superficiales cubiertas por costras amarillentas y que han ido aumentando en número y tamaño, extendiéndose rápidamente a la piel de alrededor. Ha estado rascándose las lesiones, lo que parece haberlas empeorado. También comenta que en la guardería hay otros niños que han presentado lesiones similares en la piel. El niño tiene buen estado general y no tiene fiebre, sólo se queja de picor en las lesiones. Ante este cuadro clínico, ¿cuál es el diagnóstico más probable?:', 'Impétigo contagioso.', 'Molluscum contagioso.', 'Infección por herpes virus.', 'Candidiasis mucocutánea.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 197, 'Sin clasificar', 'Hombre de 50 años que acude a la consulta por una lesión pigmentada en su pierna derecha que ha cambiado de tamaño y color en los últimos 4 meses. La lesión es de 8 mm de diámetro, asimétrica, con bordes irregulares y con varias tonalidades de marrón y negro. Además, refiere prurito ocasional en la zona. No tiene antecedentes personales de cáncer, ni otros de interés, pero su madre fue diagnosticada de melanoma a los 60 años. Se realiza una dermatoscopia que revela un patrón de red irregular, puntos negros, áreas de regresión y vasos sanguíneos irregulares. ¿Cuál es el manejo más apropiado?:', 'Biopsia mediante punción de la parte más pigmentada de la lesión para confirmar el diagnóstico.', 'Biopsia mediante escisión completa con márgenes quirúrgicos de 2 mm y estudio histopatológico.', 'Monitorización de la lesión con dermatoscopia digital y seguimiento en 3 meses.', 'Terapia fotodinámica para reducir el tamaño de la lesión antes de realizar una biopsia.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 198, 'Sin clasificar', 'Una lactante prematura de 32 semanas, consulta al mes de nacimiento por 3 hemangiomas infantiles superficiales que han crecido en las 2 últimas semanas en el antebrazo derecho, en el tórax y en la espalda. Respecto a los hemangiomas infantiles que presenta la paciente, señale la respuesta INCORRECTA:', 'Tienen 3 fases evolutivas: una fase proliferativa en la que la lesión crece aceleradamente, un periodo de estabilidad y una fase involutiva.', 'Suponen la única lesión positiva para el marcador GLUT-1 (proteína transportadora de glucosa).', 'Es necesario realizar estudios de imagen (la ecografía sería la técnica de elección) por el riesgo aumentado de hemangiomas a nivel visceral.', 'La mayoría de los hemangiomas infantiles tiene un curso clínico predecible por lo que, si no hay compromiso funcional ni estético, una opción válida es no tratar a estos pacientes. Página: 3', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 199, 'Sin clasificar', 'Hombre de 45 años con antecedentes personales de hipertensión arterial, dislipemia, hígado graso y esclerosis múltiple y en tratamiento con fingolimod, enalapril y simvastatina, presenta una psoriasis con afectación de más del 10% de la superficie corporal y un índice de la severidad del área de psoriasis (PASI) de 14. Había realizado previamente tratamiento con acitretina durante 15 meses con escasa mejoría. El paciente pregunta por otra alternativa terapéutica que consiga mejorar su psoriasis. ¿Cuál considera que es la mejor opción de tratamiento?:', 'Fototerapia.', 'Biológico con mecanismo de acción anti-TNF (factor de necrosis tumoral).', 'Ciclosporina.', 'Biológico con mecanismo de acción anti- Interleucina 23.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 200, 'Sin clasificar', 'Indique, de los siguientes, ¿cuál es un criterio de malignidad radiológica de los tumores óseos?:', 'Esclerosis perilesional reactiva.', 'Presencia de calcificaciones puntiformes en el interior de la estructura ósea.', 'Rotura de la cortical ósea.', 'Localización epifisaria del tumor por la posibilidad de afectación de la articulación.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 201, 'Sin clasificar', 'En la enfermedad por arañazo de gato, señale la INCORRECTA:', 'En los casos sin manifestaciones sistémicas de la enfermedad es suficiente con tratamiento tópico.', 'Para el diagnóstico es necesaria la práctica de una serología.', 'Si se precisa tratamiento antibiótico, se recomienda azitromicina 500 mg. en una dosis inicial y 250 mg cada 24 horas durante 4 días más.', 'La mayoría de los casos curan de forma espontánea en semanas o meses sin tratamiento de ningún tipo.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 202, 'Sin clasificar', 'Hombre de 45 años que refiere desde hace 3 meses dolor en codo derecho irradiado a antebrazo, no asociado a parestesias ni sensación subjetiva de pérdida de fuerza. La intensidad del dolor va empeorando a lo largo del día, principalmente con trabajo de ordenador y con actividades deportivas. A la exploración física no se observan signos inflamatorios externos, presenta dolor a la palpación de epitróclea humeral y se reproduce su dolor al distender y resistir la musculatura flexora de antebrazo y mano. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Epicondilopatía medial.', 'Epicondilopatía lateral.', 'Síndrome compartimental crónico.', 'Neuropatía cubital por atrapamiento en canal epitrócleo-olecraniano.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 203, 'Sin clasificar', 'Hombre de 57 años con buen estado general, tiene un PSA de 13 ng/mL y tacto rectal pétreo. El estudio diagnóstico revela cáncer de próstata de alto riesgo, Gleason 9, metastásico, con afectación ósea (más de 8 lesiones en el esqueleto axial) y metástasis hepáticas. ¿Cuál de los siguientes es el tratamiento inicial indicado en la actualidad?:', 'Prostatectomía radical con linfadenectomía extendida y resección de las metástasis.', 'Radioterapia externa pélvica y radioterapia estereotáxica de las metástasis.', 'Braquiterapia pélvica de alta tasa.', 'Antiandrógenos inicialmente más análogos de la LHRH + enzalutamida + docetaxel.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 204, 'Sin clasificar', 'Gestante de 36 años primigesta sin factores de riesgo excepto índice de masa corporal de 32 pregestacional, que acude a urgencias a las 28 semanas y presenta una rotura prematura de membranas. En el momento del ingreso la analítica es normal, no presenta dinámica uterina y la longitud cervical es de 38 mm. ¿Cuál de las siguientes afirmaciones es INCORRECTA?', 'Iniciaremos maduración pulmonar fetal con corticoides.', 'Se realizará profilaxis de corioamnionitis mediante antibioterapia endovenosa.', 'Se iniciará neuroprotección fetal.', 'Se iniciará profilaxis tromboembólica con heparina de bajo peso molecular.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 205, 'Sin clasificar', '¿Qué autoanticuerpos en las miopatías inflamatorias debería alertarnos de un curso agresivo de una neumonía intersticial asociada?:', 'Anti-TIF-1.', 'Anti MDA-5.', 'Anti-Mi2.', 'Anti-PM/SCL.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 207, 'Sin clasificar', 'En relación con el estudio de la causalidad en epidemiología, solo uno de los siguientes es un criterio o consideración causal de Bradford Hill. Señálelo:', 'Gradiente biológico (relación dosis-respuesta).', 'Ausencia de sesgos.', 'Ausencia de confusión.', 'Significación estadística de la asociación.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 208, 'Sin clasificar', 'Hombre de 80 años con antecedentes de hipertensión arterial y diabetes mellitus, así como un accidente isquémico cerebral transitorio 2 años antes. Hospitalizado actualmente tras presentar un infarto de miocardio sin elevación del segmento ST (IAMSEST). En la coronariografía se observa enfermedad arterial coronaria multivaso no revascularizable. En la analítica la función renal es normal, sin anemia. ¿Cuál es el tratamiento antiagregante que debiera recomendarse como primera opción?:', 'Ácido acetil salicílico 100 mg/día de forma indefinida.', 'Ácido acetil salicílico 100 mg/día de forma indefinida y clopidogrel 75 mg/día durante 1 año.', 'Ácido acetil salicílico 100 mg/día de forma indefinida y ticagrelor 90 mg/día durante 1 año.', 'Ácido acetil salicílico 100 mg/día de forma indefinida y prasugrel 5 mg/día durante 1 año.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 209, 'Sin clasificar', 'Hombre de 34 años con poliposis intestinal y manifestaciones extraintestinales como hipertrofia congénita de retina y osteomas mandibulares. Para hacer el diagnóstico genético se debe analizar el gen:', 'Gen MYH.', 'Gen PTEN.', 'Gen APC.', 'Gen p53.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 210, 'Sin clasificar', 'Acude por primera vez a la consulta una paciente de 17 años con anorexia nerviosa de un año de evolución. En la exploración física y analítica son característicos los siguientes signos EXCEPTO:', 'Lanugo.', 'Taquicardia.', 'Hipopotasemia si existen conductas purgativas como los vómitos o el uso de laxantes.', 'Disminución de hormonas gonadotróficas.', NULL, 'D');